  '/',
  routeMetadata(RoutePatterns.adminPanel('Create business line')),
  authMiddleware,
  enforceRouteMetadata(),
  createBusinessLine
);

router.get(
  '/',
  routeMetadata(RoutePatterns.adminPanel('Get all business lines')),
  authMiddleware,
  enforceRouteMetadata(),
  getAllBusinessLines
);

router.get(
