@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@300;400;500;600;700&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* ════════════════════════════════════════════════════════════════════════════
   LAYER 0: CSS RESET & NORMALIZATION
   Ensures consistent rendering across all browsers
   ════════════════════════════════════════════════════════════════════════════ */
@layer base {
  *,
  *::before,
  *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  html {
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
    scroll-behavior: smooth;
    font-size: 16px;
    line-height: 1.5;
  }

  body {
    min-height: 100vh;
    font-family: 'Inter', system-ui, -apple-system, sans-serif;
  }

  /* RTL Support - Arabic font */
  [dir="rtl"] body,
  [lang="ar"] body {
    font-family: 'Cairo', system-ui, sans-serif;
  }

  img,
  picture,
  video,
  canvas,
  svg {
    display: block;
    max-width: 100%;
  }

  input,
  button,
  textarea,
  select {
    font: inherit;
    color: inherit;
  }

  button {
    cursor: pointer;
    border: none;
    background: none;
  }

  a {
    color: inherit;
    text-decoration: none;
  }

  ul,
  ol {
    list-style: none;
  }

  table {
    border-collapse: collapse;
    border-spacing: 0;
  }

  /* Remove default input styles */
  input::-webkit-outer-spin-button,
  input::-webkit-inner-spin-button {
    -webkit-appearance: none;
    margin: 0;
  }
  input[type="number"] {
    -moz-appearance: textfield;
  }
}

/* ════════════════════════════════════════════════════════════════════════════
   LAYER 1: GLOBAL SEMANTIC TOKENS
   Base design tokens inherited by all panels - the foundation of the system
   ════════════════════════════════════════════════════════════════════════════ */
@layer base {
  :root {
    /* ─────────────────────────────────────────────────────────────────────
       FOUNDATION TOKENS - Core design system values
       ───────────────────────────────────────────────────────────────────── */
    --radius: 0.5rem;
    --radius-sm: 0.25rem;
    --radius-lg: 0.75rem;
    --radius-xl: 1rem;
    --radius-full: 9999px;

    --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
    --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
    --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);
    --shadow-xl: 0 20px 25px -5px rgb(0 0 0 / 0.1), 0 8px 10px -6px rgb(0 0 0 / 0.1);

    --font-sans: 'Inter', system-ui, -apple-system, sans-serif;
    --font-arabic: 'Cairo', system-ui, sans-serif;
    --font-mono: ui-monospace, SFMono-Regular, 'SF Mono', Menlo, Consolas, monospace;

    --transition-fast: 150ms ease;
    --transition-base: 200ms ease;
    --transition-slow: 300ms ease;

    /* ─────────────────────────────────────────────────────────────────────
       SPACING TOKENS - Matches Tailwind rhythm
       ───────────────────────────────────────────────────────────────────── */
    --space-0: 0;
    --space-0-5: 0.125rem;
    --space-1: 0.25rem;
    --space-1-5: 0.375rem;
    --space-2: 0.5rem;
    --space-2-5: 0.625rem;
    --space-3: 0.75rem;
    --space-4: 1rem;
    --space-5: 1.25rem;
    --space-6: 1.5rem;
    --space-8: 2rem;
    --space-10: 2.5rem;
    --space-12: 3rem;
    --space-16: 4rem;
    --space-20: 5rem;
    --space-24: 6rem;

    /* ─────────────────────────────────────────────────────────────────────
       TYPOGRAPHY TOKENS - Font sizes with line heights
       ───────────────────────────────────────────────────────────────────── */
    --text-xs: 0.75rem;
    --text-sm: 0.875rem;
    --text-base: 1rem;
    --text-lg: 1.125rem;
    --text-xl: 1.25rem;
    --text-2xl: 1.5rem;
    --text-3xl: 1.875rem;
    --text-4xl: 2.25rem;

    --leading-tight: 1.25;
    --leading-snug: 1.375;
    --leading-normal: 1.5;
    --leading-relaxed: 1.625;

    --font-normal: 400;
    --font-medium: 500;
    --font-semibold: 600;
    --font-bold: 700;

    /* ─────────────────────────────────────────────────────────────────────
       LAYOUT TOKENS - Consistent dimensions across panels
       ───────────────────────────────────────────────────────────────────── */
    --layout-sidebar-width: 16rem;
    --layout-header-height: 4rem;
    --layout-page-padding: var(--space-6);
    --layout-section-gap: var(--space-6);
    --layout-card-padding: var(--space-6);
    --layout-form-gap: var(--space-4);

    /* ─────────────────────────────────────────────────────────────────────
       COLOR TOKENS - Default palette (light theme)
       ───────────────────────────────────────────────────────────────────── */
    --color-bg: #F3F4F6;
    --color-surface: #FFFFFF;
    --color-surface-hover: #F9FAFB;
    --color-surface-active: #F3F4F6;
    --color-border: #E5E7EB;
    --color-border-strong: #D1D5DB;

    --color-text: #111827;
    --color-text-secondary: #6B7280;
    --color-text-muted: #9CA3AF;
    --color-text-disabled: #D1D5DB;

    --color-accent: #2563EB;
    --color-accent-hover: #1D4ED8;
    --color-accent-active: #1E40AF;
    --color-accent-light: #DBEAFE;

    /* ─────────────────────────────────────────────────────────────────────
       STATUS COLORS - WCAG AA Compliant (≥4.5:1 contrast ratio)

       Contrast ratios calculated against text colors:
       - Success (#15803D): 4.7:1 with white - PASSES
       - Warning (#B45309): 4.6:1 with white - PASSES
       - Danger (#DC2626): 5.3:1 with white - PASSES
       - Info (#1D4ED8): 5.9:1 with white - PASSES
       ───────────────────────────────────────────────────────────────────── */

    /* Success - WCAG AA Compliant
       Base: 4.7:1 with white text (buttons)
       Text: 7.2:1 against success-light (badges, alerts) */
    --color-success: #15803D;
    --color-success-hover: #166534;
    --color-success-light: #DCFCE7;
    --color-success-border: #BBF7D0;
    --color-text-on-success: #FFFFFF;
    --color-text-success: #14532D;

    /* Warning - WCAG AA Compliant
       Base: 4.6:1 with white text (buttons)
       Text: 7.4:1 against warning-light (badges, alerts) */
    --color-warning: #B45309;
    --color-warning-hover: #92400E;
    --color-warning-light: #FEF3C7;
    --color-warning-border: #FDE68A;
    --color-text-on-warning: #FFFFFF;
    --color-text-warning: #78350F;

    /* Danger - WCAG AA Compliant
       Base: 5.3:1 with white text (buttons)
       Text: 7.8:1 against danger-light (badges, alerts) */
    --color-danger: #DC2626;
    --color-danger-hover: #B91C1C;
    --color-danger-light: #FEE2E2;
    --color-danger-border: #FECACA;
    --color-text-on-danger: #FFFFFF;
    --color-text-danger: #7F1D1D;

    /* Info - WCAG AA Compliant
       Base: 5.9:1 with white text (buttons)
       Text: 7.5:1 against info-light (badges, alerts) */
    --color-info: #1D4ED8;
    --color-info-hover: #1E40AF;
    --color-info-light: #DBEAFE;
    --color-info-border: #BFDBFE;
    --color-text-on-info: #FFFFFF;
    --color-text-info: #1E3A8A;

    /* Accent - WCAG AA compliant (5.5:1 with white) */
    --color-text-on-accent: #FFFFFF;

    /* ─────────────────────────────────────────────────────────────────────
       COMPONENT TOKENS - Bound to semantic tokens
       ───────────────────────────────────────────────────────────────────── */

    /* Button Tokens - All status variants use WCAG AA compliant text colors */
    --btn-primary-bg: var(--color-accent);
    --btn-primary-bg-hover: var(--color-accent-hover);
    --btn-primary-text: var(--color-text-on-accent);
    --btn-secondary-bg: var(--color-surface);
    --btn-secondary-bg-hover: var(--color-surface-hover);
    --btn-secondary-text: var(--color-text);
    --btn-secondary-border: var(--color-border);
    --btn-ghost-bg: transparent;
    --btn-ghost-bg-hover: var(--color-surface-hover);
    --btn-ghost-text: var(--color-text-secondary);
    --btn-ghost-text-hover: var(--color-text);
    --btn-danger-bg: var(--color-danger);
    --btn-danger-bg-hover: var(--color-danger-hover);
    --btn-danger-text: var(--color-text-on-danger);
    --btn-success-bg: var(--color-success);
    --btn-success-bg-hover: var(--color-success-hover);
    --btn-success-text: var(--color-text-on-success);
    --btn-warning-bg: var(--color-warning);
    --btn-warning-bg-hover: var(--color-warning-hover);
    --btn-warning-text: var(--color-text-on-warning);
    --btn-info-bg: var(--color-info);
    --btn-info-bg-hover: var(--color-info-hover);
    --btn-info-text: var(--color-text-on-info);
    --btn-outline-border: var(--color-border);
    --btn-outline-border-hover: var(--color-accent);
    --btn-outline-text: var(--color-text);
    --btn-outline-text-hover: var(--color-accent);

    /* Input Tokens */
    --input-bg: var(--color-surface);
    --input-border: var(--color-border);
    --input-border-hover: var(--color-border-strong);
    --input-border-focus: var(--color-accent);
    --input-text: var(--color-text);
    --input-placeholder: var(--color-text-muted);
    --input-disabled-bg: var(--color-surface-hover);
    --input-disabled-text: var(--color-text-disabled);
    --input-error-border: var(--color-danger);
    --input-success-border: var(--color-success);

    /* Card Tokens */
    --card-bg: var(--color-surface);
    --card-border: var(--color-border);
    --card-shadow: var(--shadow-sm);
    --card-hover-shadow: var(--shadow-md);

    /* Sidebar Tokens */
    --sidebar-bg: var(--color-surface);
    --sidebar-border: var(--color-border);
    --sidebar-text: var(--color-text);
    --sidebar-item-bg: transparent;
    --sidebar-item-bg-hover: var(--color-surface-hover);
    --sidebar-item-bg-active: var(--color-accent);
    --sidebar-item-text: var(--color-text-secondary);
    --sidebar-item-text-hover: var(--color-text);
    --sidebar-item-text-active: var(--color-text-on-accent);
    --sidebar-icon-color: var(--color-text-muted);
    --sidebar-icon-color-hover: var(--color-text-secondary);
    --sidebar-icon-color-active: var(--color-text-on-accent);

    /* Table Tokens */
    --table-bg: var(--color-surface);
    --table-header-bg: var(--color-surface-hover);
    --table-header-text: var(--color-text-secondary);
    --table-row-bg: var(--color-surface);
    --table-row-bg-hover: var(--color-surface-hover);
    --table-row-bg-selected: var(--color-accent-light);
    --table-row-border: var(--color-border);
    --table-cell-text: var(--color-text);

    /* Modal/Dialog Tokens */
    --modal-bg: var(--color-surface);
    --modal-border: var(--color-border);
    --modal-shadow: var(--shadow-xl);
    --modal-overlay: rgba(0, 0, 0, 0.5);
    --modal-title-text: var(--color-text);
    --modal-body-text: var(--color-text-secondary);

    /* Badge Tokens - Uses status colors on light backgrounds (WCAG AA compliant) */
    --badge-default-bg: var(--color-surface-hover);
    --badge-default-text: var(--color-text-secondary);
    --badge-default-border: var(--color-border);
    --badge-success-bg: var(--color-success-light);
    --badge-success-text: var(--color-text-success);
    --badge-success-border: var(--color-success-border);
    --badge-warning-bg: var(--color-warning-light);
    --badge-warning-text: var(--color-text-warning);
    --badge-warning-border: var(--color-warning-border);
    --badge-danger-bg: var(--color-danger-light);
    --badge-danger-text: var(--color-text-danger);
    --badge-danger-border: var(--color-danger-border);
    --badge-info-bg: var(--color-info-light);
    --badge-info-text: var(--color-text-info);
    --badge-info-border: var(--color-info-border);

    /* Alert Tokens - Uses status colors on light backgrounds (WCAG AA compliant) */
    --alert-success-bg: var(--color-success-light);
    --alert-success-text: var(--color-text-success);
    --alert-success-border: var(--color-success-border);
    --alert-warning-bg: var(--color-warning-light);
    --alert-warning-text: var(--color-text-warning);
    --alert-warning-border: var(--color-warning-border);
    --alert-danger-bg: var(--color-danger-light);
    --alert-danger-text: var(--color-text-danger);
    --alert-danger-border: var(--color-danger-border);
    --alert-info-bg: var(--color-info-light);
    --alert-info-text: var(--color-text-info);
    --alert-info-border: var(--color-info-border);

    /* Tabs Tokens */
    --tabs-bg: transparent;
    --tabs-border: var(--color-border);
    --tabs-item-text: var(--color-text-secondary);
    --tabs-item-text-hover: var(--color-text);
    --tabs-item-text-active: var(--color-accent);
    --tabs-indicator-bg: var(--color-accent);

    /* Select/Dropdown Tokens */
    --select-bg: var(--color-surface);
    --select-border: var(--color-border);
    --select-text: var(--color-text);
    --select-placeholder: var(--color-text-muted);
    --select-option-bg: var(--color-surface);
    --select-option-bg-hover: var(--color-surface-hover);
    --select-option-bg-selected: var(--color-accent-light);
    --select-option-text: var(--color-text);
    --select-option-text-selected: var(--color-accent);

    /* Checkbox/Radio Tokens */
    --checkbox-bg: var(--color-surface);
    --checkbox-border: var(--color-border-strong);
    --checkbox-border-hover: var(--color-accent);
    --checkbox-checked-bg: var(--color-accent);
    --checkbox-checked-border: var(--color-accent);
    --checkbox-checkmark: var(--color-text-on-accent);

    /* Tooltip Tokens */
    --tooltip-bg: #1F2937;
    --tooltip-text: #FFFFFF;
    --tooltip-border: transparent;

    /* Progress/Loader Tokens */
    --progress-bg: var(--color-surface-hover);
    --progress-fill: var(--color-accent);
    --loader-color: var(--color-accent);

    /* Scrollbar Tokens */
    --scrollbar-track: var(--color-surface-hover);
    --scrollbar-thumb: var(--color-border-strong);
    --scrollbar-thumb-hover: var(--color-text-muted);

    /* ─────────────────────────────────────────────────────────────────────
       SHADCN/UI COMPATIBILITY TOKENS (HSL format)
       ───────────────────────────────────────────────────────────────────── */
    --background: 0 0% 100%;
    --foreground: 222.2 84% 4.9%;
    --card: 0 0% 100%;
    --card-foreground: 222.2 84% 4.9%;
    --popover: 0 0% 100%;
    --popover-foreground: 222.2 84% 4.9%;
    --primary: 221.2 83.2% 53.3%;
    --primary-foreground: 210 40% 98%;
    --secondary: 210 40% 96.1%;
    --secondary-foreground: 222.2 47.4% 11.2%;
    --muted: 210 40% 96.1%;
    --muted-foreground: 215.4 16.3% 46.9%;
    --accent: 210 40% 96.1%;
    --accent-foreground: 222.2 47.4% 11.2%;
    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 210 40% 98%;
    --border: 214.3 31.8% 91.4%;
    --input: 214.3 31.8% 91.4%;
    --ring: 221.2 83.2% 53.3%;
  }
}

/* ════════════════════════════════════════════════════════════════════════════
   LAYER 2: PANEL-SPECIFIC THEMES
   Override global tokens based on data-panel attribute
   ════════════════════════════════════════════════════════════════════════════ */

/* ──────────────────────────────────────────────────────────────────────────
   SYSTEM PANEL - Dark Purple Theme
   Applied when: <html data-panel="system">
   ────────────────────────────────────────────────────────────────────────── */
@layer base {
  [data-panel="system"] {
    /* Core Colors */
    --color-bg: #0D0D0D;
    --color-surface: #1A1A1A;
    --color-surface-hover: #252525;
