    --badge-danger-bg: #450A0A;
    --badge-danger-text: #F87171;
    --badge-danger-border: #B91C1C;
    --badge-info-bg: #1E3A8A;
    --badge-info-text: #93C5FD;
    --badge-info-border: #1E40AF;

    /* Alert Overrides - Dark Theme WCAG AA Compliant */
    --alert-success-bg: #052E16;
    --alert-success-text: #4ADE80;
    --alert-success-border: #166534;
    --alert-warning-bg: #451A03;
    --alert-warning-text: #FBBF24;
    --alert-warning-border: #92400E;
    --alert-danger-bg: #450A0A;
    --alert-danger-text: #F87171;
    --alert-danger-border: #B91C1C;
    --alert-info-bg: #1E3A8A;
    --alert-info-text: #93C5FD;
