/* ════════════════════════════════════════════════════════════════════════════
   LAYER 3: LEGACY TOKEN ALIASES
   For backward compatibility with existing code
   ════════════════════════════════════════════════════════════════════════════ */
@layer base {
  :root {
    /* System Panel Aliases */
    --sys-bg: var(--color-bg);
    --sys-surface: var(--color-surface);
    --sys-surface-hover: var(--color-surface-hover);
    --sys-border: var(--color-border);
