    --sys-accent-hover: var(--color-accent-hover);
    --sys-button: var(--btn-secondary-bg);
    --sys-button-hover: var(--btn-secondary-bg-hover);
    --sys-success: var(--color-success);
    --sys-warning: var(--color-warning);
    --sys-error: var(--color-danger);
    --sys-info: var(--color-info);

    /* Tenant Panel Aliases */
    --tenant-bg: var(--color-bg);
    --tenant-surface: var(--color-surface);
    --tenant-surface-hover: var(--color-surface-hover);
    --tenant-border: var(--color-border);
    --tenant-text: var(--color-text);
    --tenant-text-secondary: var(--color-text-secondary);
    --tenant-text-muted: var(--color-text-muted);
    --tenant-accent: var(--color-accent);
    --tenant-accent-hover: var(--color-accent-hover);
    --tenant-button: var(--btn-secondary-bg);
    --tenant-button-hover: var(--btn-secondary-bg-hover);
    --tenant-success: var(--color-success);
    --tenant-warning: var(--color-warning);
    --tenant-error: var(--color-danger);
    --tenant-info: var(--color-info);

    /* App Panel Aliases */
    --app-bg: var(--color-bg);
    --app-surface: var(--color-surface);
    --app-surface-hover: var(--color-surface-hover);
    --app-border: var(--color-border);
    --app-text: var(--color-text);
    --app-text-secondary: var(--color-text-secondary);
    --app-text-muted: var(--color-text-muted);
    --app-accent: var(--color-accent);
    --app-accent-hover: var(--color-accent-hover);
    --app-button: var(--btn-secondary-bg);
    --app-button-hover: var(--btn-secondary-bg-hover);
    --app-success: var(--color-success);
    --app-warning: var(--color-warning);
    --app-error: var(--color-danger);
