/* ════════════════════════════════════════════════════════════════════════════
   LAYER 4: BASE ELEMENT STYLES
   Apply token-driven styles to base HTML elements
   ════════════════════════════════════════════════════════════════════════════ */
@layer base {
  * {
    border-color: var(--color-border);
  }

  body {
    background-color: var(--color-bg);
    color: var(--color-text);
    transition: background-color var(--transition-base), color var(--transition-base);
  }

  /* Focus ring styles - WCAG AA compliant */
  *:focus-visible {
    outline: 2px solid var(--color-accent);
    outline-offset: 2px;
  }

  /* Selection styles */
  ::selection {
    background-color: var(--color-accent-light);
    color: var(--color-text);
  }

  /* Scrollbar styling */
  ::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }
  ::-webkit-scrollbar-track {
    background: var(--scrollbar-track);
  }
  ::-webkit-scrollbar-thumb {
    background: var(--scrollbar-thumb);
    border-radius: 4px;
  }
  ::-webkit-scrollbar-thumb:hover {
    background: var(--scrollbar-thumb-hover);
  }

  /* Firefox scrollbar */
  * {
    scrollbar-width: thin;
    scrollbar-color: var(--scrollbar-thumb) var(--scrollbar-track);
  }

  /* Code elements */
  code,
  pre {
    font-family: var(--font-mono);
    font-size: 0.875em;
  }
  code:not(pre code) {
    background-color: var(--color-surface-hover);
    padding: 0.125rem 0.375rem;
    border-radius: var(--radius-sm);
  }

  /* Headings */
  h1, h2, h3, h4, h5, h6 {
    color: var(--color-text);
    font-weight: 600;
    line-height: 1.25;
  }

  /* Paragraph */
  p {
    color: var(--color-text-secondary);
    line-height: 1.625;
  }

  /* Links */
  a:not([class]) {
    color: var(--color-accent);
    transition: color var(--transition-fast);
  }
  a:not([class]):hover {
    color: var(--color-accent-hover);
  }
}

/* ════════════════════════════════════════════════════════════════════════════
   LAYER 5: UTILITY CLASSES
   Token-driven utility classes for flexible styling
   ════════════════════════════════════════════════════════════════════════════ */
@layer utilities {
  /* Background utilities */
  .bg-panel { background-color: var(--color-bg); }
  .bg-surface { background-color: var(--color-surface); }
  .bg-surface-hover { background-color: var(--color-surface-hover); }
  .bg-accent { background-color: var(--color-accent); }
  .bg-accent-light { background-color: var(--color-accent-light); }
  .bg-success { background-color: var(--color-success); }
  .bg-success-light { background-color: var(--color-success-light); }
  .bg-warning { background-color: var(--color-warning); }
  .bg-warning-light { background-color: var(--color-warning-light); }
  .bg-danger { background-color: var(--color-danger); }
  .bg-danger-light { background-color: var(--color-danger-light); }
  .bg-info { background-color: var(--color-info); }
  .bg-info-light { background-color: var(--color-info-light); }

  /* Text utilities */
  .text-panel { color: var(--color-text); }
  .text-secondary { color: var(--color-text-secondary); }
  .text-muted { color: var(--color-text-muted); }
  .text-accent { color: var(--color-accent); }
  .text-success { color: var(--color-text-success); }
  .text-warning { color: var(--color-text-warning); }
  .text-danger { color: var(--color-text-danger); }
  .text-info { color: var(--color-text-info); }
  .text-on-accent { color: var(--color-text-on-accent); }
  .text-on-success { color: var(--color-text-on-success); }
  .text-on-warning { color: var(--color-text-on-warning); }
  .text-on-danger { color: var(--color-text-on-danger); }
  .text-on-info { color: var(--color-text-on-info); }

  /* Border utilities */
  .border-panel { border-color: var(--color-border); }
  .border-strong { border-color: var(--color-border-strong); }
  .border-accent { border-color: var(--color-accent); }
  .border-success { border-color: var(--color-success-border); }
  .border-warning { border-color: var(--color-warning-border); }
  .border-danger { border-color: var(--color-danger-border); }
  .border-info { border-color: var(--color-info-border); }

  /* Card utilities */
  .card-panel {
    background-color: var(--card-bg);
    border: 1px solid var(--card-border);
    box-shadow: var(--card-shadow);
    border-radius: var(--radius);
  }
  .card-panel-hover:hover {
    box-shadow: var(--card-hover-shadow);
  }

  /* Button utilities */
  .btn-primary {
    background: var(--btn-primary-bg);
    color: var(--btn-primary-text);
    border-radius: var(--radius);
    transition: all var(--transition-fast);
  }
  .btn-primary:hover {
    background: var(--btn-primary-bg-hover);
  }
  .btn-secondary {
    background-color: var(--btn-secondary-bg);
    color: var(--btn-secondary-text);
    border: 1px solid var(--btn-secondary-border);
    border-radius: var(--radius);
    transition: all var(--transition-fast);
  }
  .btn-secondary:hover {
    background-color: var(--btn-secondary-bg-hover);
  }
  .btn-ghost {
    background-color: var(--btn-ghost-bg);
    color: var(--btn-ghost-text);
    border-radius: var(--radius);
    transition: all var(--transition-fast);
  }
  .btn-ghost:hover {
    background-color: var(--btn-ghost-bg-hover);
    color: var(--btn-ghost-text-hover);
  }
  .btn-danger {
    background-color: var(--btn-danger-bg);
    color: var(--btn-danger-text);
    border-radius: var(--radius);
    transition: all var(--transition-fast);
  }
  .btn-danger:hover {
    background-color: var(--btn-danger-bg-hover);
  }
  .btn-success {
    background-color: var(--btn-success-bg);
    color: var(--btn-success-text);
    border-radius: var(--radius);
    transition: all var(--transition-fast);
  }
  .btn-success:hover {
    background-color: var(--btn-success-bg-hover);
  }
  .btn-warning {
    background-color: var(--btn-warning-bg);
    color: var(--btn-warning-text);
    border-radius: var(--radius);
    transition: all var(--transition-fast);
  }
  .btn-warning:hover {
    background-color: var(--btn-warning-bg-hover);
  }
  .btn-info {
    background-color: var(--btn-info-bg);
    color: var(--btn-info-text);
    border-radius: var(--radius);
    transition: all var(--transition-fast);
  }
  .btn-info:hover {
    background-color: var(--btn-info-bg-hover);
  }

  /* Input utilities */
  .input-panel {
    background-color: var(--input-bg);
    border: 1px solid var(--input-border);
    color: var(--input-text);
    border-radius: var(--radius);
    transition: border-color var(--transition-fast);
  }
  .input-panel::placeholder {
    color: var(--input-placeholder);
  }
  .input-panel:hover {
    border-color: var(--input-border-hover);
  }
  .input-panel:focus {
    border-color: var(--input-border-focus);
    outline: none;
    box-shadow: 0 0 0 2px var(--color-accent-light);
  }
  .input-error {
    border-color: var(--input-error-border);
  }
  .input-success {
    border-color: var(--input-success-border);
  }

  /* Table utilities */
  .table-header {
    background-color: var(--table-header-bg);
    color: var(--table-header-text);
  }
  .table-row {
    background-color: var(--table-row-bg);
    border-bottom: 1px solid var(--table-row-border);
    transition: background-color var(--transition-fast);
  }
  .table-row:hover {
    background-color: var(--table-row-bg-hover);
  }
  .table-row-selected {
    background-color: var(--table-row-bg-selected);
  }
  .table-cell {
    color: var(--table-cell-text);
  }

  /* Sidebar utilities */
  .sidebar-panel {
    background-color: var(--sidebar-bg);
    border-color: var(--sidebar-border);
  }
  .sidebar-item {
    background-color: var(--sidebar-item-bg);
    color: var(--sidebar-item-text);
    transition: all var(--transition-fast);
  }
  .sidebar-item:hover {
    background-color: var(--sidebar-item-bg-hover);
    color: var(--sidebar-item-text-hover);
  }
  .sidebar-item-active {
    background: var(--sidebar-item-bg-active);
    color: var(--sidebar-item-text-active);
  }

  /* Modal utilities */
  .modal-panel {
    background-color: var(--modal-bg);
    border: 1px solid var(--modal-border);
    box-shadow: var(--modal-shadow);
    border-radius: var(--radius-lg);
  }
  .modal-overlay {
    background-color: var(--modal-overlay);
  }

  /* Badge utilities */
  .badge-default {
    background-color: var(--badge-default-bg);
    color: var(--badge-default-text);
    border: 1px solid var(--badge-default-border);
  }
  .badge-success {
    background-color: var(--badge-success-bg);
    color: var(--badge-success-text);
    border: 1px solid var(--badge-success-border);
  }
  .badge-warning {
    background-color: var(--badge-warning-bg);
    color: var(--badge-warning-text);
    border: 1px solid var(--badge-warning-border);
  }
  .badge-danger {
    background-color: var(--badge-danger-bg);
    color: var(--badge-danger-text);
    border: 1px solid var(--badge-danger-border);
  }
  .badge-info {
    background-color: var(--badge-info-bg);
    color: var(--badge-info-text);
    border: 1px solid var(--badge-info-border);
  }

  /* Alert utilities */
  .alert-success {
    background-color: var(--alert-success-bg);
    color: var(--alert-success-text);
    border: 1px solid var(--alert-success-border);
  }
  .alert-warning {
    background-color: var(--alert-warning-bg);
    color: var(--alert-warning-text);
    border: 1px solid var(--alert-warning-border);
  }
  .alert-danger {
    background-color: var(--alert-danger-bg);
    color: var(--alert-danger-text);
    border: 1px solid var(--alert-danger-border);
  }
  .alert-info {
    background-color: var(--alert-info-bg);
    color: var(--alert-info-text);
    border: 1px solid var(--alert-info-border);
  }

  /* Transition utilities */
  .transition-fast { transition: all var(--transition-fast); }
  .transition-base { transition: all var(--transition-base); }
  .transition-slow { transition: all var(--transition-slow); }

  /* Shadow utilities */
  .shadow-panel { box-shadow: var(--card-shadow); }
  .shadow-panel-hover:hover { box-shadow: var(--card-hover-shadow); }
}

/* ════════════════════════════════════════════════════════════════════════════
   LAYER 6: COMPONENT OVERRIDES
   Ensure Shadcn/UI components use our token system
   ════════════════════════════════════════════════════════════════════════════ */
@layer components {
  /* Button component binding */
  .button-primary {
    background: var(--btn-primary-bg) !important;
    color: var(--btn-primary-text) !important;
  }
  .button-primary:hover {
    background: var(--btn-primary-bg-hover) !important;
  }

  /* Dialog/Modal component binding */
  [role="dialog"] {
    background-color: var(--modal-bg);
    border-color: var(--modal-border);
  }

  /* Popover component binding */
  [data-radix-popper-content-wrapper] [role="listbox"],
  [data-radix-popper-content-wrapper] [role="menu"] {
    background-color: var(--color-surface);
    border-color: var(--color-border);
  }

  /* Select option hover */
  [role="option"]:hover,
  [role="menuitem"]:hover {
    background-color: var(--color-surface-hover);
  }

  /* Active/selected states */
  [data-state="checked"],
  [aria-selected="true"] {
    background-color: var(--color-accent-light);
    color: var(--color-accent);
  }
}

