/**
 * Hierarchy Service
 * Manages the multi-tenant hierarchy: Tenant → Business Line → Branch → User
 * Handles creation, validation, and hierarchy resolution
 */

import { db } from '../db';
import { eq, and } from 'drizzle-orm';
import { tenants, businessLines, branches, users, tenantQuotas } from '../db/schemas';
import { auditService } from '../core/audit';
import { RequestContext } from '../core/context';
import { contextLogger } from '../core/context';
import bcrypt from 'bcryptjs';
import { v4 as uuidv4 } from 'uuid';

export interface CreateTenantInput {
  code: string;
  name: string;
  country?: string;
  timezone?: string;
  subscriptionPlan?: string;
  contactEmail?: string;
  contactPhone?: string;
  address?: string;
}

export interface CreateBusinessLineInput {
  tenantId: string;
  code: string;
  name: string;
  businessLineType?: string;
  description?: string;
  contactEmail?: string;
  contactPhone?: string;
}

export interface CreateBranchInput {
  businessLineId: string;
  code: string;
  name: string;
  city?: string;
  state?: string;
  country?: string;
  postalCode?: string;
  address?: string;
  phone?: string;
  email?: string;
  timezone?: string;
}

export interface CreateUserInput {
  branchId: string;
  code?: string;
  firstName: string;
  lastName: string;
  email: string;
  phone?: string;
  password: string;
  role?: string;
  accessScope?: string;
}

export class HierarchyService {
  /**
   * Create a new tenant with quota initialization
   */
  static async createTenant(input: CreateTenantInput) {
    const tenantId = uuidv4();

    const [tenant] = await db.insert(tenants).values({
      id: tenantId,
      code: input.code,
      name: input.name,
      country: input.country,
      timezone: input.timezone || 'UTC',
      subscriptionPlan: input.subscriptionPlan || 'trial',
      status: 'active',
      contactEmail: input.contactEmail,
      contactPhone: input.contactPhone,
      address: input.address,
    }).returning();

    await db.insert(tenantQuotas).values({
      id: uuidv4(),
      tenantId: tenant.id,
      planTier: input.subscriptionPlan || 'trial',
      maxUsers: this.getQuotaByPlan(input.subscriptionPlan || 'trial').maxUsers,
      maxBranches: this.getQuotaByPlan(input.subscriptionPlan || 'trial').maxBranches,
    });

    await auditService.log({
      action: 'create',
      resourceType: 'tenant',
      resourceId: tenant.id,
      newData: tenant as unknown as Record<string, unknown>,
      severity: 'high',
      metadata: { tenantId: tenant.id },
    });

    contextLogger.info('Tenant created', { tenantId: tenant.id, code: tenant.code });

    return tenant;
  }

  /**
   * Create a new business line under a tenant
   */
  static async createBusinessLine(input: CreateBusinessLineInput) {
    const tenant = await db.query.tenants.findFirst({
      where: eq(tenants.id, input.tenantId),
    });

    if (!tenant) {
      throw new Error('Tenant not found');
    }

    const [businessLine] = await db.insert(businessLines).values({
      tenantId: input.tenantId,
      code: input.code,
      name: input.name,
      businessLineType: input.businessLineType || 'general',
      description: input.description,
      contactEmail: input.contactEmail,
      contactPhone: input.contactPhone,
    }).returning();

    await auditService.log({
      action: 'create',
      resourceType: 'business_line',
      resourceId: businessLine.id,
      newData: businessLine as unknown as Record<string, unknown>,
      severity: 'medium',
      metadata: { tenantId: input.tenantId, businessLineId: businessLine.id },
    });

    contextLogger.info('Business line created', { 
      businessLineId: businessLine.id, 
      tenantId: input.tenantId 
    });

    return businessLine;
  }

  /**
   * Create a new branch under a business line
   * Automatically resolves tenantId from parent business line
   */
  static async createBranch(input: CreateBranchInput) {
    const businessLine = await db.query.businessLines.findFirst({
      where: eq(businessLines.id, input.businessLineId),
    });

    if (!businessLine) {
      throw new Error('Business line not found');
    }

    const tenantId = businessLine.tenantId;

    const [branch] = await db.insert(branches).values({
      tenantId,
      businessLineId: input.businessLineId,
      code: input.code,
      name: input.name,
      city: input.city,
      state: input.state,
      country: input.country,
      postalCode: input.postalCode,
      address: input.address,
      phone: input.phone,
      email: input.email,
      timezone: input.timezone,
    }).returning();

    await auditService.log({
      action: 'create',
      resourceType: 'branch',
      resourceId: branch.id,
      newData: branch as unknown as Record<string, unknown>,
      severity: 'medium',
      metadata: { tenantId, businessLineId: input.businessLineId, branchId: branch.id },
    });

    contextLogger.info('Branch created', { 
      branchId: branch.id, 
      businessLineId: input.businessLineId,
      tenantId 
    });

    return branch;
  }

  /**
   * Create a new user under a branch
   * Automatically resolves businessLineId and tenantId from parent branch
   */
  static async createUser(input: CreateUserInput) {
    const branch = await db.query.branches.findFirst({
      where: eq(branches.id, input.branchId),
    });

    if (!branch) {
      throw new Error('Branch not found');
    }

    const tenantId = branch.tenantId;
    const businessLineId = branch.businessLineId;

    const existingUser = await db.query.users.findFirst({
      where: eq(users.email, input.email),
    });

    if (existingUser) {
      throw new Error('User with this email already exists');
    }

    const passwordHash = await bcrypt.hash(input.password, 12);
    const userCode = input.code || `USR-${Date.now().toString(36).toUpperCase()}`;

    const [user] = await db.insert(users).values({
      code: userCode,
      firstName: input.firstName,
      lastName: input.lastName,
      email: input.email,
      phone: input.phone,
      passwordHash,
      role: input.role || 'staff',
      accessScope: input.accessScope || 'branch',
      status: 'active',
      isActive: true,
      branchId: input.branchId,
      businessLineId,
      tenantId,
    }).returning();

    await auditService.log({
      action: 'create',
      resourceType: 'user',
      resourceId: user.id,
      newData: { ...user, passwordHash: '[REDACTED]' } as unknown as Record<string, unknown>,
      severity: 'high',
      metadata: { tenantId, businessLineId, branchId: input.branchId, userId: user.id },
    });

    contextLogger.info('User created', { 
      userId: user.id, 
      branchId: input.branchId,
      businessLineId,
      tenantId 
    });

    return { ...user, passwordHash: undefined };
  }

  /**
   * Get full hierarchy for a tenant
   */
  static async getTenantHierarchy(tenantId: string) {
    const tenant = await db.query.tenants.findFirst({
      where: eq(tenants.id, tenantId),
    });

    if (!tenant) {
      return null;
    }

    const tenantBusinessLines = await db.query.businessLines.findMany({
      where: eq(businessLines.tenantId, tenantId),
    });

    const hierarchy = await Promise.all(
      tenantBusinessLines.map(async (bl) => {
        const blBranches = await db.query.branches.findMany({
          where: and(
            eq(branches.tenantId, tenantId),
            eq(branches.businessLineId, bl.id)
          ),
        });

        const branchesWithUsers = await Promise.all(
          blBranches.map(async (branch) => {
            const branchUsers = await db.query.users.findMany({
              where: eq(users.branchId, branch.id),
              columns: {
                id: true,
                code: true,
                firstName: true,
                lastName: true,
                email: true,
                role: true,
                accessScope: true,
                isActive: true,
              },
            });

            return {
              ...branch,
              users: branchUsers,
              userCount: branchUsers.length,
            };
          })
        );

        return {
          ...bl,
          branches: branchesWithUsers,
          branchCount: branchesWithUsers.length,
          totalUsers: branchesWithUsers.reduce((sum, b) => sum + b.userCount, 0),
        };
      })
    );

    return {
      ...tenant,
      businessLines: hierarchy,
      businessLineCount: hierarchy.length,
      totalBranches: hierarchy.reduce((sum, bl) => sum + bl.branchCount, 0),
      totalUsers: hierarchy.reduce((sum, bl) => sum + bl.totalUsers, 0),
    };
  }

  /**
   * Resolve user hierarchy context
   */
  static async resolveUserContext(userId: string) {
    const user = await db.query.users.findFirst({
      where: eq(users.id, userId),
    });

    if (!user) return null;

    let branch = null;
    let businessLine = null;
    let tenant = null;

    if (user.branchId) {
      branch = await db.query.branches.findFirst({
        where: eq(branches.id, user.branchId),
      });
    }

    if (user.businessLineId) {
      businessLine = await db.query.businessLines.findFirst({
        where: eq(businessLines.id, user.businessLineId),
      });
    }

    if (user.tenantId) {
      tenant = await db.query.tenants.findFirst({
        where: eq(tenants.id, user.tenantId),
      });
    }

    return {
      user: { ...user, passwordHash: undefined },
      branch,
      businessLine,
      tenant,
    };
  }

  /**
   * Get quota limits by subscription plan
   */
  private static getQuotaByPlan(plan: string) {
    const quotas: Record<string, { maxUsers: number; maxBranches: number }> = {
      trial: { maxUsers: 5, maxBranches: 1 },
      standard: { maxUsers: 25, maxBranches: 3 },
      professional: { maxUsers: 100, maxBranches: 10 },
      enterprise: { maxUsers: 1000, maxBranches: 100 },
    };
    return quotas[plan] || quotas.trial;
  }

  /**
   * Validate branch capacity before adding user
   */
  static async validateBranchCapacity(branchId: string): Promise<boolean> {
    const branch = await db.query.branches.findFirst({
      where: eq(branches.id, branchId),
    });

    if (!branch) return false;

    const quota = await db.query.tenantQuotas.findFirst({
      where: eq(tenantQuotas.tenantId, branch.tenantId),
    });

    if (!quota) return true;

    const userCount = await db.query.users.findMany({
      where: eq(users.tenantId, branch.tenantId),
    });

    return userCount.length < quota.maxUsers;
  }
}

export default HierarchyService;

server/src/services/ScopeService.ts.content:
/**
 * RBAC Scope Service - AGI-Ready with Hot Path Caching
 * Phase 7: Implements multi-level access scoping with L1/L2 cache integration
 * 
 * Scope Levels: tenant > business_line > branch > mixed
 * 
 * Performance Target: 99%+ cache hit ratio for getScopeFilter()
 */

import { db } from '../db';
import { eq, and, inArray } from 'drizzle-orm';
import { users, branches, businessLines, tenants } from '../db/schemas';
import { RequestContext } from '../core/context';
import { contextLogger } from '../core/context';
import { cacheService } from '../core/cache';
import { CACHE_KEYS, CACHE_TAGS } from '../core/cache/types';

export type ScopeType = 'tenant' | 'business_line' | 'branch' | 'mixed';

export interface ScopeContext {
  scopeType: ScopeType;
  tenantId: string;
  businessLineId?: string | null;
  branchId?: string | null;
  allowedBranchIds?: string[];
}

export interface ScopeFilter {
  tenantId: string;
  businessLineIds?: string[];
  branchIds?: string[];
}

const SCOPE_CACHE_TTL = 2 * 60 * 1000;
const SCOPE_STALE_TIME = 5 * 60 * 1000;

export class ScopeService {
  /**
   * Resolve tenant ID for a user - from context or database
   * Used to ensure consistent tenant scoping even in background jobs
   */
  private static async resolveTenantId(userId: string): Promise<string | null> {
    const contextTenantId = RequestContext.getTenantId();
    if (contextTenantId) return contextTenantId;

    const user = await db.query.users.findFirst({
      where: eq(users.id, userId),
      columns: { tenantId: true },
    });
    return user?.tenantId || null;
  }

  /**
   * Resolve user's effective scope context (CACHED)
   * Returns the scope boundaries for data access
   */
  static async resolveUserScope(userId: string): Promise<ScopeContext | null> {
    const tenantId = await this.resolveTenantId(userId);
    if (!tenantId) {
      return null;
    }

    const cacheKey = CACHE_KEYS.scopeContext(tenantId, userId);

    return cacheService.getStale(
      cacheKey,
      async () => {
        const user = await db.query.users.findFirst({
          where: eq(users.id, userId),
        });

        if (!user || !user.tenantId) {
          return null;
        }

        const scopeContext: ScopeContext = {
          scopeType: (user.accessScope as ScopeType) || 'branch',
          tenantId: user.tenantId,
          businessLineId: user.businessLineId,
          branchId: user.branchId,
          allowedBranchIds: (user.allowedBranchIds as string[]) || [],
        };

        return scopeContext;
      },
      {
        ttl: SCOPE_CACHE_TTL,
        staleWhileRevalidate: true,
        staleTime: SCOPE_STALE_TIME,
        tags: [CACHE_TAGS.SCOPES, CACHE_TAGS.USERS],
        priority: 'critical',
        tenantScoped: true,
        explicitTenantId: tenantId,
      }
    );
  }

  /**
   * Get scope filter for database queries (HOT PATH - AGGRESSIVELY CACHED)
   * This determines which records the user can access
   * 
   * Performance: L1 cache hit target 99%+
   */
  static async getScopeFilter(userId: string): Promise<ScopeFilter | null> {
    const tenantId = await this.resolveTenantId(userId);
    if (!tenantId) {
      return null;
    }

    const cacheKey = CACHE_KEYS.scopeFilter(tenantId, userId);

    return cacheService.getStale(
      cacheKey,
      async () => {
        const scopeContext = await this.resolveUserScopeUncached(userId);
        if (!scopeContext) return null;

        const filter: ScopeFilter = {
          tenantId: scopeContext.tenantId,
        };

        switch (scopeContext.scopeType) {
          case 'tenant':
            break;

          case 'business_line':
            if (scopeContext.businessLineId) {
              const branchesInLine = await db.query.branches.findMany({
                where: and(
                  eq(branches.tenantId, scopeContext.tenantId),
                  eq(branches.businessLineId, scopeContext.businessLineId)
                ),
              });
              filter.businessLineIds = [scopeContext.businessLineId];
              filter.branchIds = branchesInLine.map(b => b.id);
            }
            break;

          case 'branch':
            if (scopeContext.branchId) {
              filter.branchIds = [scopeContext.branchId];
              if (scopeContext.businessLineId) {
                filter.businessLineIds = [scopeContext.businessLineId];
              }
            }
            break;

          case 'mixed':
            if (scopeContext.allowedBranchIds && scopeContext.allowedBranchIds.length > 0) {
              filter.branchIds = scopeContext.allowedBranchIds;
              const allowedBranches = await db.query.branches.findMany({
                where: inArray(branches.id, scopeContext.allowedBranchIds),
              });
              filter.businessLineIds = [...new Set(allowedBranches.map(b => b.businessLineId).filter(Boolean))] as string[];
            }
            break;
        }

        return filter;
      },
      {
        ttl: SCOPE_CACHE_TTL,
        staleWhileRevalidate: true,
        staleTime: SCOPE_STALE_TIME,
        tags: [CACHE_TAGS.SCOPES, CACHE_TAGS.HIERARCHY],
        priority: 'critical',
        tenantScoped: true,
        explicitTenantId: tenantId,
      }
    );
  }

  /**
   * Internal uncached scope filter for fallback
   */
  private static async getScopeFilterUncached(userId: string): Promise<ScopeFilter | null> {
    const scopeContext = await this.resolveUserScopeUncached(userId);
    if (!scopeContext) return null;

    const filter: ScopeFilter = { tenantId: scopeContext.tenantId };

    switch (scopeContext.scopeType) {
      case 'tenant':
        break;
      case 'business_line':
        if (scopeContext.businessLineId) {
          const branchesInLine = await db.query.branches.findMany({
            where: and(
              eq(branches.tenantId, scopeContext.tenantId),
              eq(branches.businessLineId, scopeContext.businessLineId)
            ),
          });
          filter.businessLineIds = [scopeContext.businessLineId];
          filter.branchIds = branchesInLine.map(b => b.id);
        }
        break;
      case 'branch':
        if (scopeContext.branchId) {
          filter.branchIds = [scopeContext.branchId];
          if (scopeContext.businessLineId) {
            filter.businessLineIds = [scopeContext.businessLineId];
          }
        }
        break;
      case 'mixed':
        if (scopeContext.allowedBranchIds && scopeContext.allowedBranchIds.length > 0) {
          filter.branchIds = scopeContext.allowedBranchIds;
          const allowedBranches = await db.query.branches.findMany({
            where: inArray(branches.id, scopeContext.allowedBranchIds),
          });
          filter.businessLineIds = [...new Set(allowedBranches.map(b => b.businessLineId).filter(Boolean))] as string[];
        }
        break;
    }

    return filter;
  }

  /**
   * Internal uncached scope resolution for cache factory
   */
  private static async resolveUserScopeUncached(userId: string): Promise<ScopeContext | null> {
    const user = await db.query.users.findFirst({
      where: eq(users.id, userId),
    });

    if (!user || !user.tenantId) {
      return null;
    }

    return {
      scopeType: (user.accessScope as ScopeType) || 'branch',
      tenantId: user.tenantId,
      businessLineId: user.businessLineId,
      branchId: user.branchId,
      allowedBranchIds: (user.allowedBranchIds as string[]) || [],
    };
  }

  /**
   * Invalidate scope cache for a user
   * Called when user's scope or assignments change
   */
  static async invalidateUserScope(userId: string, tenantId?: string): Promise<void> {
    const tid = tenantId || RequestContext.getTenantId();
    if (!tid) {
      await cacheService.invalidateByTags([CACHE_TAGS.SCOPES]);
      contextLogger.debug('User scope cache invalidated via tags (no tenant context)', { userId });
      return;
    }

    await cacheService.delete(CACHE_KEYS.scopeFilter(tid, userId));
    await cacheService.delete(CACHE_KEYS.scopeContext(tid, userId));
    await cacheService.delete(CACHE_KEYS.userBranches(tid, userId));
    await cacheService.delete(CACHE_KEYS.userBusinessLines(tid, userId));

    contextLogger.debug('User scope cache invalidated', { userId, tenantId: tid });
  }

  /**
   * Invalidate all scope caches for a tenant
   * Called when tenant hierarchy changes
   */
  static async invalidateTenantScopes(tenantId: string): Promise<void> {
    await cacheService.invalidateByTags([CACHE_TAGS.SCOPES]);
    contextLogger.debug('Tenant scope caches invalidated', { tenantId });
  }

  /**
   * Check if user can access a specific resource (CACHED)
   */
  static async canAccessResource(
    userId: string,
    resourceTenantId: string,
    resourceBusinessLineId?: string | null,
    resourceBranchId?: string | null
  ): Promise<boolean> {
    const scopeFilter = await this.getScopeFilter(userId);
    if (!scopeFilter) return false;

    if (scopeFilter.tenantId !== resourceTenantId) {
      return false;
    }

    const scopeContext = await this.resolveUserScope(userId);
    if (!scopeContext) return false;

    switch (scopeContext.scopeType) {
      case 'tenant':
        return true;

      case 'business_line':
        if (resourceBusinessLineId) {
          return scopeFilter.businessLineIds?.includes(resourceBusinessLineId) || false;
        }
        return true;

      case 'branch':
        if (resourceBranchId) {
          return scopeFilter.branchIds?.includes(resourceBranchId) || false;
        }
        if (resourceBusinessLineId) {
          return scopeFilter.businessLineIds?.includes(resourceBusinessLineId) || false;
        }
        return true;

      case 'mixed':
        if (resourceBranchId) {
          return scopeFilter.branchIds?.includes(resourceBranchId) || false;
        }
        return true;
    }

    return false;
  }

  /**
   * Get all branches accessible by user (CACHED)
   */
  static async getAccessibleBranches(userId: string): Promise<string[]> {
    const tenantId = await this.resolveTenantId(userId);
    if (!tenantId) {
      return [];
    }

    const cacheKey = CACHE_KEYS.userBranches(tenantId, userId);

    return cacheService.getStale(
      cacheKey,
      async () => {
        const scopeFilter = await this.getScopeFilter(userId);
        if (!scopeFilter) return [];

        if (!scopeFilter.branchIds) {
          const allBranches = await db.query.branches.findMany({
            where: eq(branches.tenantId, scopeFilter.tenantId),
          });
          return allBranches.map(b => b.id);
        }

        return scopeFilter.branchIds;
      },
      {
        ttl: SCOPE_CACHE_TTL,
        staleWhileRevalidate: true,
        staleTime: SCOPE_STALE_TIME,
        tags: [CACHE_TAGS.SCOPES, CACHE_TAGS.HIERARCHY],
        priority: 'high',
        tenantScoped: true,
        explicitTenantId: tenantId,
      }
    );
  }

  /**
   * Get all business lines accessible by user (CACHED)
   */
  static async getAccessibleBusinessLines(userId: string): Promise<string[]> {
    const tenantId = await this.resolveTenantId(userId);
    if (!tenantId) {
      return [];
    }

    const cacheKey = CACHE_KEYS.userBusinessLines(tenantId, userId);

    return cacheService.getStale(
      cacheKey,
      async () => {
        const scopeFilter = await this.getScopeFilter(userId);
        if (!scopeFilter) return [];

        if (!scopeFilter.businessLineIds) {
          const allLines = await db.query.businessLines.findMany({
            where: eq(businessLines.tenantId, scopeFilter.tenantId),
          });
          return allLines.map(bl => bl.id);
        }

        return scopeFilter.businessLineIds;
      },
      {
        ttl: SCOPE_CACHE_TTL,
        staleWhileRevalidate: true,
        staleTime: SCOPE_STALE_TIME,
        tags: [CACHE_TAGS.SCOPES, CACHE_TAGS.HIERARCHY],
        priority: 'high',
        tenantScoped: true,
        explicitTenantId: tenantId,
      }
    );
  }

  /**
   * Build Drizzle query filter based on user scope
   */
  static buildScopeCondition(
    scopeFilter: ScopeFilter,
    options: {
      tenantIdColumn: any;
      businessLineIdColumn?: any;
      branchIdColumn?: any;
    }
  ) {
    const conditions: any[] = [eq(options.tenantIdColumn, scopeFilter.tenantId)];

    if (scopeFilter.branchIds && options.branchIdColumn) {
      conditions.push(inArray(options.branchIdColumn, scopeFilter.branchIds));
    }

    if (scopeFilter.businessLineIds && options.businessLineIdColumn && !scopeFilter.branchIds) {
      conditions.push(inArray(options.businessLineIdColumn, scopeFilter.businessLineIds));
    }

    return and(...conditions);
  }

  /**
   * Log scope evaluation for audit
   */
  static async logScopeEvaluation(
    userId: string,
    action: string,
    resource: string,
    allowed: boolean
  ): Promise<void> {
    const traceId = RequestContext.getTraceId();
    contextLogger.info('Scope evaluation', {
      traceId,
      userId,
      action,
      resource,
      allowed,
    });
  }
}

export default ScopeService;

