import { Activity, Cpu, HardDrive, Wifi } from 'lucide-react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';

const getTrendStyle = (trend: string) => {
  switch (trend) {
    case 'low':
      return { backgroundColor: 'var(--badge-success-bg)', color: 'var(--color-text-success)' };
    case 'high':
      return { backgroundColor: 'var(--badge-warning-bg)', color: 'var(--color-text-warning)' };
    default:
      return { backgroundColor: 'var(--badge-info-bg)', color: 'var(--color-text-info)' };
  }
};

export default function SystemMetricsPage() {
  const metrics = [
    { name: 'API Response Time', value: '45ms', trend: 'stable', icon: Activity },
    { name: 'CPU Usage', value: '23%', trend: 'low', icon: Cpu },
    { name: 'Memory Usage', value: '512MB', trend: 'stable', icon: HardDrive },
    { name: 'Active Connections', value: '127', trend: 'high', icon: Wifi },
  ];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold" style={{ color: 'var(--sys-text)' }}>Platform Metrics</h1>
        <p className="mt-2" style={{ color: 'var(--sys-text-secondary)' }}>
          Real-time system performance and usage statistics
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {metrics.map((metric) => {
          const Icon = metric.icon;
          const trendStyle = getTrendStyle(metric.trend);
          return (
            <Card 
              key={metric.name} 
              className="border"
              style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}
            >
              <CardContent className="pt-6">
                <div className="flex items-center justify-between mb-4">
                  <div 
                    className="w-10 h-10 rounded-lg flex items-center justify-center"
                    style={{ backgroundColor: 'color-mix(in srgb, var(--sys-accent) 20%, transparent)' }}
                  >
                    <Icon className="w-5 h-5" style={{ color: 'var(--sys-accent)' }} />
                  </div>
                  <span 
                    className="px-2 py-1 text-xs rounded"
                    style={trendStyle}
                  >
                    {metric.trend}
                  </span>
                </div>
                <p className="text-2xl font-bold" style={{ color: 'var(--sys-text)' }}>{metric.value}</p>
                <p className="text-sm mt-1" style={{ color: 'var(--sys-text-secondary)' }}>{metric.name}</p>
              </CardContent>
            </Card>
          );
        })}
      </div>

      <Card className="border" style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}>
        <CardHeader>
          <CardTitle style={{ color: 'var(--sys-text)' }}>Performance Overview</CardTitle>
          <CardDescription style={{ color: 'var(--sys-text-secondary)' }}>
            System performance charts will be displayed here
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div 
            className="h-64 flex items-center justify-center border-2 border-dashed rounded-lg"
            style={{ borderColor: 'var(--sys-border)' }}
          >
            <p style={{ color: 'var(--sys-text-muted)' }}>Performance charts - Coming in Phase 3</p>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/layouts/SystemAdminLayout.tsx.content:
import { Outlet, Link, useLocation, useNavigate } from 'react-router-dom';
import { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Building2, 
  Users, 
  Shield,
  Settings,
  Activity,
  Database,
  Menu,
  X,
  ChevronRight,
  LogOut,
  Globe
} from 'lucide-react';
import { useAuth } from '@/contexts/AuthContext';

export default function SystemAdminLayout() {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isMobile, setIsMobile] = useState(false);
  const [isRTL, setIsRTL] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  useEffect(() => {
    document.documentElement.setAttribute('data-panel', 'system');
    return () => {
      document.documentElement.removeAttribute('data-panel');
    };
  }, []);

  useEffect(() => {
    const checkRTL = () => {
      const dir = document.documentElement.getAttribute('dir') || 'ltr';
      const lang = document.documentElement.lang || 'en';
      setIsRTL(dir === 'rtl' || lang === 'ar');
    };

    checkRTL();
    const observer = new MutationObserver(checkRTL);
    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ['dir', 'lang'],
    });
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth < 1024;
      setIsMobile(mobile);
      if (mobile) {
        setIsSidebarOpen(false);
      } else {
        setIsSidebarOpen(true);
      }
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const navigation = [
    { name: 'System Dashboard', href: '/system/dashboard', icon: LayoutDashboard, nameAr: 'لوحة النظام' },
    { name: 'Tenants', href: '/system/tenants', icon: Building2, nameAr: 'العملاء' },
    { name: 'Platform Users', href: '/system/users', icon: Users, nameAr: 'مستخدمو النظام' },
    { name: 'Roles & Permissions', href: '/system/roles', icon: Shield, nameAr: 'الأدوار والصلاحيات' },
    { name: 'DPF Manager', href: '/system/dpf', icon: Database, nameAr: 'إدارة DPF' },
    { name: 'Platform Metrics', href: '/system/metrics', icon: Activity, nameAr: 'مقاييس النظام' },
    { name: 'System Settings', href: '/system/settings', icon: Settings, nameAr: 'إعدادات النظام' },
  ];

  const isActiveRoute = (href: string) => {
    if (href === '/system/dashboard') {
      return location.pathname === '/system/dashboard' || location.pathname === '/system';
    }
    return location.pathname.startsWith(href);
  };

  const handleLogout = async () => {
    await logout();
    navigate('/login');
  };

  return (
    <div className={`min-h-screen flex bg-panel ${isRTL ? 'flex-row-reverse' : 'flex-row'}`}>
      <aside
        className={`
          ${isSidebarOpen ? 'translate-x-0' : isRTL ? 'translate-x-full' : '-translate-x-full'}
          ${isMobile ? 'fixed inset-y-0 z-50 w-64' : 'relative w-64'}
          ${isRTL ? 'border-l' : 'border-r'}
          transition-transform duration-300 ease-in-out
          flex flex-col bg-surface border-panel
        `}
      >
