import { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Users, Plus, Search, Eye, Edit, Shield, User, Building2, ArrowRight } from 'lucide-react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Select } from '@/components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { useAllUsers, useTenants } from '@/hooks/useHierarchy';
import { LoadingState } from '@/components/ui/loading-state';
import { EmptyState } from '@/components/ui/empty-state';
import { ErrorState } from '@/components/ui/error-state';

type UserTypeSelection = 'system' | 'tenant_admin' | null;

const getScopeStyle = (scope: string) => {
  switch (scope) {
    case 'system':
      return { backgroundColor: 'color-mix(in srgb, var(--sys-accent) 20%, transparent)', color: 'var(--sys-accent)', borderColor: 'color-mix(in srgb, var(--sys-accent) 30%, transparent)' };
    case 'tenant':
      return { backgroundColor: 'var(--badge-info-bg)', color: 'var(--color-text-info)', borderColor: 'var(--badge-info-border)' };
    case 'business_line':
      return { backgroundColor: 'color-mix(in srgb, var(--color-info) 20%, transparent)', color: 'var(--color-info)', borderColor: 'color-mix(in srgb, var(--color-info) 30%, transparent)' };
    case 'branch':
      return { backgroundColor: 'var(--badge-success-bg)', color: 'var(--color-text-success)', borderColor: 'var(--badge-success-border)' };
    case 'mixed':
      return { backgroundColor: 'var(--badge-warning-bg)', color: 'var(--color-text-warning)', borderColor: 'var(--badge-warning-border)' };
    default:
      return { backgroundColor: 'var(--badge-success-bg)', color: 'var(--color-text-success)', borderColor: 'var(--badge-success-border)' };
  }
};

const getStatusStyle = (status: string) => {
  switch (status) {
    case 'active':
      return { backgroundColor: 'var(--badge-success-bg)', color: 'var(--color-text-success)', borderColor: 'var(--badge-success-border)' };
    case 'inactive':
      return { backgroundColor: 'var(--sys-button)', color: 'var(--sys-text-muted)', borderColor: 'var(--sys-border)' };
    case 'suspended':
      return { backgroundColor: 'var(--badge-danger-bg)', color: 'var(--color-text-danger)', borderColor: 'var(--badge-danger-border)' };
    case 'pending':
      return { backgroundColor: 'var(--badge-warning-bg)', color: 'var(--color-text-warning)', borderColor: 'var(--badge-warning-border)' };
    default:
      return { backgroundColor: 'var(--badge-success-bg)', color: 'var(--color-text-success)', borderColor: 'var(--badge-success-border)' };
  }
};

const userTypes = [
  {
    id: 'system' as const,
    icon: Shield,
    title: 'System User',
    description: 'Platform-level user with system-wide access. No tenant or branch assignment required.',
    details: [
      'Full platform access',
      'Can manage all tenants',
      'No branch restriction',
    ],
  },
  {
    id: 'tenant_admin' as const,
    icon: Building2,
    title: 'Tenant Admin',
    description: 'Organization administrator with full access to their tenant. Assigned to a specific tenant.',
    details: [
      'Full tenant access',
      'Can manage all branches',
      'Auto-granted permissions',
    ],
  },
];

export default function SystemUsersListPage() {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedTenantId, setSelectedTenantId] = useState('');
  const [showUserTypeSelector, setShowUserTypeSelector] = useState(false);
  const [selectedType, setSelectedType] = useState<UserTypeSelection>(null);

  const { data: users, isLoading, error } = useAllUsers();
  const { data: tenants } = useTenants();

  const tenantOptions = useMemo(() => {
    if (!tenants) return [];
    return tenants.map(t => ({ value: t.id, label: `${t.name} (${t.code})` }));
  }, [tenants]);

  const filteredUsers = useMemo(() => {
    if (!users) return [];
    let result = users;

    if (selectedTenantId) {
      result = result.filter(u => u.tenantId === selectedTenantId);
    }

    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      result = result.filter(
        (u) =>
          u.email.toLowerCase().includes(query) ||
          u.name?.toLowerCase().includes(query) ||
          u.code?.toLowerCase().includes(query) ||
          u.firstName?.toLowerCase().includes(query) ||
          u.lastName?.toLowerCase().includes(query)
      );
    }

    return result;
  }, [users, searchQuery, selectedTenantId]);

  const getUserDisplayName = (u: any) => {
    if (u.name) return u.name;
    if (u.firstName && u.lastName) return `${u.firstName} ${u.lastName}`;
    if (u.firstName) return u.firstName;
    return u.email.split('@')[0];
  };

  const handleContinue = () => {
    if (!selectedType) return;
    setShowUserTypeSelector(false);
    navigate(`/system/users/create?type=${selectedType}`);
    setSelectedType(null);
  };

  const handleCancel = () => {
    setSelectedType(null);
    setShowUserTypeSelector(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold" style={{ color: 'var(--sys-text)' }}>Platform Users</h1>
          <p className="mt-2" style={{ color: 'var(--sys-text-secondary)' }}>
            Manage system users, tenant admins, and all platform accounts
          </p>
        </div>
        <Button 
          onClick={() => setShowUserTypeSelector(true)}
          style={{ 
            background: 'linear-gradient(135deg, var(--sys-accent), var(--sys-accent-hover))', 
            color: 'var(--color-text-on-accent)' 
          }}
        >
          <Plus className="w-4 h-4 mr-2" />
          Add User
        </Button>
      </div>

      <Card className="border" style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}>
        <CardContent className="pt-6">
          <div className="space-y-4">
            <div className="flex gap-4">
              <div className="flex-1 relative">
                <Search 
                  className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" 
                  style={{ color: 'var(--sys-text-muted)' }} 
                />
                <Input
                  placeholder="Search users by name, email, or code..."
                  className="pl-10"
                  style={{ 
                    backgroundColor: 'var(--sys-bg)', 
                    borderColor: 'var(--sys-border)', 
                    color: 'var(--sys-text)' 
                  }}
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
            </div>
            <div className="flex gap-4 flex-wrap">
              {tenantOptions.length > 0 && (
                <div className="w-56">
                  <Select
                    value={selectedTenantId}
                    onChange={(e) => setSelectedTenantId(e.target.value)}
                    style={{ 
                      backgroundColor: 'var(--sys-bg)', 
                      borderColor: 'var(--sys-border)', 
                      color: 'var(--sys-text)' 
                    }}
                  >
                    <option value="">All Tenants</option>
                    {tenantOptions.map((opt) => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </Select>
                </div>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      <Card className="border" style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}>
        <CardHeader>
          <CardTitle style={{ color: 'var(--sys-text)' }}>Users</CardTitle>
          <CardDescription style={{ color: 'var(--sys-text-secondary)' }}>
            {filteredUsers.length} user{filteredUsers.length !== 1 ? 's' : ''} found
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <LoadingState size="lg" message="Loading users..." fullPage />
          ) : error ? (
            <ErrorState
              title="Error Loading Users"
              message={(error as any)?.message || 'Failed to load users. Please try again.'}
              retryAction={() => window.location.reload()}
              variant="page"
            />
          ) : filteredUsers.length === 0 ? (
            <EmptyState
              icon={Users}
              title={searchQuery ? 'No Matching Users' : 'No Users Yet'}
              description={searchQuery ? 'Try adjusting your search' : 'Create your first user to get started'}
              action={!searchQuery ? {
                label: 'Add User',
                onClick: () => setShowUserTypeSelector(true),
                icon: Plus,
              } : undefined}
            />
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow style={{ borderColor: 'var(--sys-border)' }}>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>User</TableHead>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>Code</TableHead>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>Scope</TableHead>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>Contact</TableHead>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>Role</TableHead>
                    <TableHead className="text-center" style={{ color: 'var(--sys-text-secondary)' }}>Status</TableHead>
                    <TableHead className="text-right" style={{ color: 'var(--sys-text-secondary)' }}>Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredUsers.map((u) => (
                    <TableRow 
                      key={u.id} 
                      className="transition-colors"
                      onMouseEnter={(e) => e.currentTarget.style.backgroundColor = 'var(--sys-surface-hover)'}
                      onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                      style={{ borderColor: 'var(--sys-border)' }}
                    >
                      <TableCell className="font-medium">
                        <div className="flex items-center gap-3">
                          {u.avatarUrl ? (
                            <img src={u.avatarUrl} alt={getUserDisplayName(u)} className="w-9 h-9 rounded-full object-cover" />
                          ) : (
                            <div 
                              className="w-9 h-9 rounded-full flex items-center justify-center"
                              style={{ backgroundColor: 'color-mix(in srgb, var(--sys-accent) 20%, transparent)' }}
                            >
                              <User className="w-4 h-4" style={{ color: 'var(--sys-accent)' }} />
                            </div>
                          )}
                          <div>
                            <p className="font-medium" style={{ color: 'var(--sys-text)' }}>{getUserDisplayName(u)}</p>
                            <p className="text-xs" style={{ color: 'var(--sys-text-muted)' }}>{u.email}</p>
                          </div>
                        </div>
                      </TableCell>
                      <TableCell>
                        {u.code ? (
                          <code 
                            className="text-sm px-2 py-1 rounded"
                            style={{ backgroundColor: 'var(--sys-bg)', color: 'var(--sys-text-secondary)' }}
                          >
                            {u.code}
                          </code>
                        ) : (
                          <span style={{ color: 'var(--sys-text-muted)' }}>-</span>
                        )}
                      </TableCell>
                      <TableCell>
                        <Badge className="border" style={getScopeStyle(u.accessScope)}>
                          {u.accessScope || 'branch'}
                        </Badge>
                      </TableCell>
                      <TableCell style={{ color: 'var(--sys-text-secondary)' }}>
                        {u.phone || <span style={{ color: 'var(--sys-text-muted)' }}>-</span>}
                      </TableCell>
                      <TableCell>
                        {u.roleCount ? (
                          <span className="flex items-center gap-1" style={{ color: 'var(--sys-text-secondary)' }}>
                            <Shield className="w-3 h-3" />
                            {u.roleCount} role{u.roleCount !== 1 ? 's' : ''}
                          </span>
                        ) : (
                          <span style={{ color: 'var(--sys-text-muted)' }}>No roles</span>
                        )}
                      </TableCell>
                      <TableCell className="text-center">
                        <Badge className="border" style={getStatusStyle(u.status)}>
                          {u.status || 'active'}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-right">
                        <div className="flex items-center justify-end gap-1">
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => navigate(`/system/users/${u.id}`)}
                            title="View"
                            style={{ color: 'var(--sys-text-secondary)' }}
                          >
                            <Eye className="w-4 h-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => navigate(`/system/users/${u.id}/edit`)}
                            title="Edit"
                            style={{ color: 'var(--sys-text-secondary)' }}
                          >
                            <Edit className="w-4 h-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => navigate(`/system/users/${u.id}/roles`)}
                            title="Manage Roles"
                            style={{ color: 'var(--sys-text-secondary)' }}
                          >
                            <Shield className="w-4 h-4" />
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>

      <Dialog open={showUserTypeSelector} onOpenChange={setShowUserTypeSelector}>
        <DialogContent 
          className="sm:max-w-2xl border"
          style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}
        >
          <DialogHeader>
            <DialogTitle className="text-xl flex items-center gap-2" style={{ color: 'var(--sys-text)' }}>
              <Users className="w-5 h-5" />
              Select User Type
            </DialogTitle>
            <DialogDescription style={{ color: 'var(--sys-text-secondary)' }}>
              Choose the type of user you want to create. Each type has different access levels and requirements.
            </DialogDescription>
          </DialogHeader>

          <div className="grid gap-4 py-4">
            {userTypes.map((type) => {
              const Icon = type.icon;
              const isSelected = selectedType === type.id;
              const isSystem = type.id === 'system';

              return (
                <button
                  key={type.id}
                  onClick={() => setSelectedType(type.id)}
                  className="relative p-4 rounded-lg border-2 text-left transition-all duration-200"
                  style={{ 
                    backgroundColor: isSelected 
                      ? 'color-mix(in srgb, var(--sys-accent) 10%, transparent)'
                      : 'var(--sys-bg)',
                    borderColor: isSelected 
                      ? 'color-mix(in srgb, var(--sys-accent) 50%, transparent)'
                      : 'var(--sys-border)'
                  }}
                >
                  <div className="flex items-start gap-4">
                    <div 
                      className="p-3 rounded-lg"
                      style={{ 
                        background: 'linear-gradient(135deg, var(--sys-accent), var(--sys-accent-hover))',
                        color: 'var(--color-text-on-accent)'
                      }}
                    >
                      <Icon className="w-6 h-6" />
                    </div>
                    <div className="flex-1">
                      <h3 className="font-semibold text-lg mb-1" style={{ color: 'var(--sys-text)' }}>
                        {type.title}
                      </h3>
                      <p className="text-sm mb-3" style={{ color: 'var(--sys-text-secondary)' }}>
                        {type.description}
                      </p>
                      <ul className="space-y-1">
                        {type.details.map((detail, i) => (
                          <li 
                            key={i} 
                            className="text-xs flex items-center gap-2"
                            style={{ color: 'var(--sys-text-muted)' }}
                          >
                            <span 
                              className="w-1.5 h-1.5 rounded-full"
                              style={{ backgroundColor: 'var(--sys-text-muted)' }}
                            />
                            {detail}
                          </li>
                        ))}
                      </ul>
                    </div>
                    {isSelected && (
                      <div className="absolute top-4 right-4">
                        <div 
                          className="w-6 h-6 rounded-full flex items-center justify-center"
                          style={{ backgroundColor: 'var(--sys-accent)' }}
                        >
                          <svg className="w-4 h-4" fill="var(--color-text-on-accent)" viewBox="0 0 20 20">
                            <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                          </svg>
                        </div>
                      </div>
                    )}
                  </div>
                </button>
              );
            })}
          </div>

          <div className="flex justify-end gap-3 pt-4 border-t" style={{ borderColor: 'var(--sys-border)' }}>
            <Button 
              variant="outline" 
              onClick={handleCancel}
              style={{ 
                backgroundColor: 'var(--sys-button)', 
                borderColor: 'var(--sys-border)', 
                color: 'var(--sys-text)' 
              }}
            >
              Cancel
            </Button>
            <Button 
              onClick={handleContinue}
              disabled={!selectedType}
              style={{ 
                background: selectedType ? 'linear-gradient(135deg, var(--sys-accent), var(--sys-accent-hover))' : 'var(--sys-button)',
                color: 'var(--color-text-on-accent)',
                opacity: selectedType ? 1 : 0.5
              }}
            >
              Continue
              <ArrowRight className="w-4 h-4 ml-2" />
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/system/SystemCreateUser.content:
import { useState, useMemo, useEffect } from 'react';
import { useNavigate, useSearchParams, Link } from 'react-router-dom';
import { ArrowLeft, Loader2, AlertCircle, Shield, Building2 } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { useTenants } from '@/hooks/useHierarchy';
import { apiClient } from '@/lib/api';

type UserType = 'system' | 'tenant_admin';

const systemRoleOptions = [
  { value: 'SYSTEM_ADMIN', label: 'System Administrator - Full platform access' },
];

function getUserTypeInfo(type: UserType) {
  if (type === 'system') {
    return {
      icon: Shield,
      title: 'Create System User',
      description: 'Platform-level user with system-wide access',
      isSystem: true,
    };
  }
  return {
    icon: Building2,
    title: 'Create Tenant Admin',
    description: 'Organization administrator with full tenant access',
    isSystem: false,
  };
}

export default function SystemCreateUserPage() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();

  const userTypeParam = searchParams.get('type') as UserType | null;
  const userType: UserType = userTypeParam === 'tenant_admin' ? 'tenant_admin' : 'system';

  const typeInfo = getUserTypeInfo(userType);
  const TypeIcon = typeInfo.icon;

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    confirmPassword: '',
    phone: '',
    roleCode: 'SYSTEM_ADMIN',
    tenantId: '',
  });

  const [error, setError] = useState<string | null>(null);
  const [passwordError, setPasswordError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);

  const { data: tenants } = useTenants();

  const nonSystemTenants = useMemo(() => {
    if (!tenants) return [];
    return tenants.filter(t => t.code !== 'SYSTEM');
  }, [tenants]);

  const tenantOptions = useMemo(() => {
    return nonSystemTenants.map(t => ({ value: t.id, label: `${t.name} (${t.code})` }));
  }, [nonSystemTenants]);

  useEffect(() => {
    if (userType === 'tenant_admin' && !formData.tenantId && nonSystemTenants.length > 0) {
      setFormData(prev => ({ ...prev, tenantId: nonSystemTenants[0].id }));
    }
  }, [nonSystemTenants, userType]);

  const handleChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (field === 'password' || field === 'confirmPassword') {
      setPasswordError(null);
    }
    setError(null);
  };

  const validateForm = () => {
    if (!formData.firstName.trim()) {
      setError('First name is required');
      return false;
    }
    if (!formData.lastName.trim()) {
      setError('Last name is required');
      return false;
    }
    if (!formData.email.trim()) {
      setError('Email is required');
      return false;
    }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      setError('Please enter a valid email address');
      return false;
    }
    if (!formData.password) {
      setError('Password is required');
      return false;
    }
    if (formData.password.length < 8) {
      setError('Password must be at least 8 characters');
      return false;
    }
    if (formData.password !== formData.confirmPassword) {
      setPasswordError('Passwords do not match');
      return false;
    }

    if (userType === 'tenant_admin' && !formData.tenantId) {
      setError('Please select a tenant');
      return false;
    }

    return true;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setPasswordError(null);

    if (!validateForm()) return;

    setIsSubmitting(true);

    try {
      if (userType === 'system') {
        await apiClient.post('/api/v1/hierarchy/system-users', {
          firstName: formData.firstName,
          lastName: formData.lastName,
          email: formData.email,
          password: formData.password,
          phone: formData.phone || undefined,
          roleCode: formData.roleCode,
        });
      } else {
        await apiClient.post('/api/v1/hierarchy/tenant-admins', {
          firstName: formData.firstName,
          lastName: formData.lastName,
          email: formData.email,
          password: formData.password,
          phone: formData.phone || undefined,
          tenantId: formData.tenantId,
        });
      }
      setSuccess(true);
      setTimeout(() => navigate('/system/users'), 1500);
    } catch (err: any) {
      setError(err?.response?.data?.error || err?.message || 'Failed to create user');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-4">
        <Link to="/system/users">
          <Button 
            variant="ghost" 
            className="p-2"
            style={{ color: 'var(--sys-text-secondary)' }}
          >
            <ArrowLeft className="w-5 h-5" />
          </Button>
        </Link>
        <div className="flex items-center gap-4">
          <div 
            className="p-3 rounded-lg"
            style={{ 
              background: 'linear-gradient(135deg, var(--sys-accent), var(--sys-accent-hover))',
              color: 'var(--color-text-on-accent)'
            }}
          >
            <TypeIcon className="w-6 h-6" />
          </div>
          <div>
            <h1 className="text-3xl font-bold" style={{ color: 'var(--sys-text)' }}>
              {typeInfo.title}
            </h1>
            <p className="mt-1" style={{ color: 'var(--sys-text-secondary)' }}>
              {typeInfo.description}
            </p>
          </div>
        </div>
      </div>

      <div 
        className="p-4 rounded-lg border"
        style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}
      >
        <div className="flex items-start gap-3">
          <TypeIcon className="w-5 h-5 mt-0.5" style={{ color: 'var(--sys-text-secondary)' }} />
          <div>
            <h4 className="font-medium" style={{ color: 'var(--sys-text)' }}>
              {userType === 'system' ? 'System User Information' : 'Tenant Admin Information'}
            </h4>
            <p className="text-sm mt-1" style={{ color: 'var(--sys-text-secondary)' }}>
              {userType === 'system' 
                ? 'System users have platform-wide access and are not assigned to any tenant or branch. They can manage all tenants and system configurations.'
                : 'Tenant admins have full access to their assigned tenant. They are automatically granted the TENANT_ADMIN role with all permissions within their organization.'
              }
            </p>
          </div>
        </div>
      </div>

      {success && (
        <div 
          className="p-4 rounded-lg border flex items-center gap-2"
          style={{ 
            backgroundColor: 'var(--alert-success-bg)', 
            borderColor: 'var(--alert-success-border)', 
            color: 'var(--color-text-success)' 
          }}
        >
          <Shield className="w-5 h-5" />
          <span>User created successfully! Redirecting...</span>
        </div>
      )}

      <form onSubmit={handleSubmit}>
        <Card className="border" style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}>
          <CardHeader>
            <CardTitle style={{ color: 'var(--sys-text)' }}>User Information</CardTitle>
            <CardDescription style={{ color: 'var(--sys-text-secondary)' }}>Enter the basic details for the new user</CardDescription>
          </CardHeader>
          <CardContent className="space-y-6">
            {error && (
              <div 
                className="p-3 rounded-lg border flex items-center gap-2"
                style={{ 
                  backgroundColor: 'var(--alert-danger-bg)', 
                  borderColor: 'var(--alert-danger-border)', 
                  color: 'var(--color-text-danger)' 
                }}
              >
                <AlertCircle className="w-4 h-4" />
                <span>{error}</span>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="firstName" style={{ color: 'var(--sys-text-secondary)' }}>First Name *</Label>
                <Input
                  id="firstName"
                  value={formData.firstName}
                  onChange={(e) => handleChange('firstName', e.target.value)}
                  placeholder="Enter first name"
                  style={{ 
                    backgroundColor: 'var(--sys-bg)', 
                    borderColor: 'var(--sys-border)', 
                    color: 'var(--sys-text)' 
                  }}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="lastName" style={{ color: 'var(--sys-text-secondary)' }}>Last Name *</Label>
                <Input
                  id="lastName"
                  value={formData.lastName}
                  onChange={(e) => handleChange('lastName', e.target.value)}
                  placeholder="Enter last name"
                  style={{ 
                    backgroundColor: 'var(--sys-bg)', 
                    borderColor: 'var(--sys-border)', 
                    color: 'var(--sys-text)' 
                  }}
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="email" style={{ color: 'var(--sys-text-secondary)' }}>Email Address *</Label>
                <Input
                  id="email"
                  type="email"
                  value={formData.email}
                  onChange={(e) => handleChange('email', e.target.value)}
                  placeholder="user@example.com"
                  style={{ 
                    backgroundColor: 'var(--sys-bg)', 
                    borderColor: 'var(--sys-border)', 
                    color: 'var(--sys-text)' 
                  }}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="phone" style={{ color: 'var(--sys-text-secondary)' }}>Phone Number</Label>
                <Input
                  id="phone"
                  type="tel"
                  value={formData.phone}
                  onChange={(e) => handleChange('phone', e.target.value)}
                  placeholder="+1 234 567 8900"
                  style={{ 
                    backgroundColor: 'var(--sys-bg)', 
                    borderColor: 'var(--sys-border)', 
                    color: 'var(--sys-text)' 
                  }}
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="password" style={{ color: 'var(--sys-text-secondary)' }}>Password *</Label>
                <Input
                  id="password"
                  type="password"
                  value={formData.password}
                  onChange={(e) => handleChange('password', e.target.value)}
                  placeholder="Minimum 8 characters"
                  style={{ 
                    backgroundColor: 'var(--sys-bg)', 
                    borderColor: 'var(--sys-border)', 
                    color: 'var(--sys-text)' 
                  }}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="confirmPassword" style={{ color: 'var(--sys-text-secondary)' }}>Confirm Password *</Label>
                <Input
                  id="confirmPassword"
                  type="password"
                  value={formData.confirmPassword}
                  onChange={(e) => handleChange('confirmPassword', e.target.value)}
                  placeholder="Repeat password"
                  style={{ 
                    backgroundColor: 'var(--sys-bg)', 
                    borderColor: passwordError ? 'var(--sys-error)' : 'var(--sys-border)', 
                    color: 'var(--sys-text)' 
                  }}
                />
                {passwordError && (
                  <p className="text-sm" style={{ color: 'var(--sys-error)' }}>{passwordError}</p>
                )}
              </div>
            </div>
          </CardContent>
        </Card>

        {userType === 'system' && (
          <Card className="mt-6 border" style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}>
            <CardHeader>
              <CardTitle className="flex items-center gap-2" style={{ color: 'var(--sys-text)' }}>
                <Shield className="w-5 h-5" style={{ color: 'var(--sys-accent)' }} />
                System Role
              </CardTitle>
              <CardDescription style={{ color: 'var(--sys-text-secondary)' }}>Select the system-level role for this user</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="roleCode" style={{ color: 'var(--sys-text-secondary)' }}>System Role *</Label>
                <Select
                  value={formData.roleCode}
                  onChange={(e) => handleChange('roleCode', e.target.value)}
                  style={{ 
                    backgroundColor: 'var(--sys-bg)', 
                    borderColor: 'var(--sys-border)', 
                    color: 'var(--sys-text)' 
                  }}
                >
                  {systemRoleOptions.map((opt) => (
                    <option key={opt.value} value={opt.value}>{opt.label}</option>
                  ))}
                </Select>
              </div>
              <div 
                className="p-3 rounded-lg border"
                style={{ backgroundColor: 'var(--sys-bg)', borderColor: 'var(--sys-border)' }}
              >
                <p className="text-sm" style={{ color: 'var(--sys-text-secondary)' }}>
                  System users are automatically assigned to the SYSTEM tenant and have platform-wide access based on their role.
                </p>
              </div>
            </CardContent>
          </Card>
        )}

        {userType === 'tenant_admin' && (
          <Card className="mt-6 border" style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}>
            <CardHeader>
              <CardTitle className="flex items-center gap-2" style={{ color: 'var(--sys-text)' }}>
                <Building2 className="w-5 h-5" style={{ color: 'var(--color-info)' }} />
                Tenant Assignment
              </CardTitle>
              <CardDescription style={{ color: 'var(--sys-text-secondary)' }}>Select the tenant this admin will manage</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label style={{ color: 'var(--sys-text-secondary)' }}>Tenant *</Label>
                <Select
                  value={formData.tenantId}
                  onChange={(e) => handleChange('tenantId', e.target.value)}
                  style={{ 
                    backgroundColor: 'var(--sys-bg)', 
                    borderColor: 'var(--sys-border)', 
                    color: 'var(--sys-text)' 
                  }}
                >
                  <option value="">Select Tenant</option>
                  {tenantOptions.map((opt) => (
                    <option key={opt.value} value={opt.value}>{opt.label}</option>
                  ))}
                </Select>
              </div>
              <div 
                className="p-3 rounded-lg border"
                style={{ backgroundColor: 'var(--badge-info-bg)', borderColor: 'var(--badge-info-border)' }}
              >
                <div className="flex items-center gap-2 mb-2" style={{ color: 'var(--color-info)' }}>
                  <Shield className="w-4 h-4" />
                  <span className="font-medium">TENANT_ADMIN Role</span>
                  <Badge 
                    className="text-xs"
                    style={{ backgroundColor: 'var(--color-info)', color: 'var(--color-text-on-accent)' }}
                  >
                    Auto-Assigned
                  </Badge>
                </div>
                <p className="text-sm" style={{ color: 'var(--color-text-info)' }}>
                  This user will be automatically assigned the TENANT_ADMIN role with full permissions within their tenant.
                </p>
              </div>
            </CardContent>
          </Card>
        )}

        <div className="flex justify-end gap-3 mt-6">
          <Link to="/system/users">
            <Button 
              type="button" 
              variant="outline"
              style={{ 
                backgroundColor: 'var(--sys-button)', 
                borderColor: 'var(--sys-border)', 
                color: 'var(--sys-text)' 
              }}
            >
              Cancel
            </Button>
          </Link>
          <Button
            type="submit"
            disabled={isSubmitting || success}
            style={{ 
              background: 'linear-gradient(135deg, var(--sys-accent), var(--sys-accent-hover))', 
              color: 'var(--color-text-on-accent)',
              opacity: isSubmitting || success ? 0.5 : 1
            }}
          >
            {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
            Create {userType === 'system' ? 'System User' : 'Tenant Admin'}
          </Button>
        </div>
      </form>
    </div>
  );
}

client/src/pages/system/SystemTenantsLis.content:
import { useState, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Building2, Plus, Search, Eye, Edit } from 'lucide-react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { useTenants } from '@/hooks/useHierarchy';
import { LoadingState } from '@/components/ui/loading-state';
import { EmptyState } from '@/components/ui/empty-state';
import { ErrorState } from '@/components/ui/error-state';

const getStatusStyle = (status: string) => {
  switch (status) {
    case 'active':
      return { backgroundColor: 'var(--badge-success-bg)', color: 'var(--color-text-success)', borderColor: 'var(--badge-success-border)' };
    case 'inactive':
      return { backgroundColor: 'var(--sys-button)', color: 'var(--sys-text-muted)', borderColor: 'var(--sys-border)' };
    case 'suspended':
      return { backgroundColor: 'var(--badge-danger-bg)', color: 'var(--color-text-danger)', borderColor: 'var(--badge-danger-border)' };
    case 'pending':
      return { backgroundColor: 'var(--badge-warning-bg)', color: 'var(--color-text-warning)', borderColor: 'var(--badge-warning-border)' };
    default:
      return { backgroundColor: 'var(--badge-success-bg)', color: 'var(--color-text-success)', borderColor: 'var(--badge-success-border)' };
  }
};

const getPlanStyle = (plan: string) => {
  switch (plan) {
    case 'trial':
      return { backgroundColor: 'var(--sys-button)', color: 'var(--sys-text-muted)', borderColor: 'var(--sys-border)' };
    case 'standard':
      return { backgroundColor: 'var(--badge-info-bg)', color: 'var(--color-text-info)', borderColor: 'var(--badge-info-border)' };
    case 'professional':
      return { backgroundColor: 'color-mix(in srgb, var(--sys-accent) 20%, transparent)', color: 'var(--sys-accent)', borderColor: 'color-mix(in srgb, var(--sys-accent) 30%, transparent)' };
    case 'enterprise':
      return { backgroundColor: 'var(--badge-warning-bg)', color: 'var(--color-text-warning)', borderColor: 'var(--badge-warning-border)' };
    default:
      return { backgroundColor: 'var(--badge-info-bg)', color: 'var(--color-text-info)', borderColor: 'var(--badge-info-border)' };
  }
};

export default function SystemTenantsListPage() {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState('');
  const { data: tenants, isLoading, error } = useTenants();

  const filteredTenants = useMemo(() => {
    if (!tenants) return [];
    if (!searchQuery) return tenants;
    const query = searchQuery.toLowerCase();
    return tenants.filter(
      (tenant) =>
        tenant.name.toLowerCase().includes(query) ||
        tenant.code.toLowerCase().includes(query) ||
        tenant.contactEmail?.toLowerCase().includes(query)
    );
  }, [tenants, searchQuery]);

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold" style={{ color: 'var(--sys-text)' }}>
            Tenants
          </h1>
          <p className="mt-2" style={{ color: 'var(--sys-text-secondary)' }}>
            Manage organizations in the platform
          </p>
        </div>
        <Link to="/system/tenants/create">
          <Button 
            style={{ 
              background: 'linear-gradient(135deg, var(--sys-accent), var(--sys-accent-hover))', 
              color: 'var(--color-text-on-accent)' 
            }}
          >
            <Plus className="w-4 h-4 mr-2" />
            Add Tenant
          </Button>
        </Link>
      </div>

      <Card className="border" style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}>
        <CardContent className="pt-6">
          <div className="flex gap-4">
            <div className="flex-1 relative">
              <Search 
                className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" 
                style={{ color: 'var(--sys-text-muted)' }} 
              />
              <Input
                placeholder="Search tenants by name, code, or email..."
                className="pl-10"
                style={{ 
                  backgroundColor: 'var(--sys-bg)', 
                  borderColor: 'var(--sys-border)', 
                  color: 'var(--sys-text)' 
                }}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>
        </CardContent>
      </Card>

      <Card className="border" style={{ backgroundColor: 'var(--sys-surface)', borderColor: 'var(--sys-border)' }}>
        <CardHeader>
          <CardTitle style={{ color: 'var(--sys-text)' }}>Tenants List</CardTitle>
          <CardDescription style={{ color: 'var(--sys-text-secondary)' }}>
            {filteredTenants.length} organization{filteredTenants.length !== 1 ? 's' : ''} found
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <LoadingState size="lg" message="Loading tenants..." fullPage />
          ) : error ? (
            <ErrorState
              title="Error Loading Tenants"
              message={(error as any)?.message || 'Failed to load tenants. Please try again.'}
              retryAction={() => window.location.reload()}
              variant="page"
            />
          ) : filteredTenants.length === 0 ? (
            <EmptyState
              icon={Building2}
              title={searchQuery ? 'No Matching Tenants' : 'No Tenants Yet'}
              description={searchQuery ? 'Try adjusting your search query' : 'Get started by creating your first tenant'}
              action={!searchQuery ? {
                label: 'Add Tenant',
                onClick: () => navigate('/system/tenants/create'),
                icon: Plus,
              } : undefined}
            />
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow style={{ borderColor: 'var(--sys-border)' }}>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>Organization</TableHead>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>Code</TableHead>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>Contact</TableHead>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>Plan</TableHead>
                    <TableHead className="text-center" style={{ color: 'var(--sys-text-secondary)' }}>Status</TableHead>
                    <TableHead style={{ color: 'var(--sys-text-secondary)' }}>Created</TableHead>
                    <TableHead className="text-right" style={{ color: 'var(--sys-text-secondary)' }}>Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredTenants.map((tenant) => (
                    <TableRow 
                      key={tenant.id} 
                      className="transition-colors"
                      onMouseEnter={(e) => e.currentTarget.style.backgroundColor = 'var(--sys-surface-hover)'}
                      onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                      style={{ borderColor: 'var(--sys-border)' }}
                    >
                      <TableCell className="font-medium">
                        <div className="flex items-center gap-3">
                          <div 
                            className="w-9 h-9 rounded-lg flex items-center justify-center text-sm font-bold"
                            style={{ 
                              backgroundColor: tenant.primaryColor || 'var(--sys-accent)',
                              color: 'var(--color-text-on-accent)'
                            }}
                          >
                            {tenant.name.charAt(0)}
                          </div>
                          <div>
                            <p className="font-medium" style={{ color: 'var(--sys-text)' }}>{tenant.name}</p>
                            <p className="text-xs" style={{ color: 'var(--sys-text-muted)' }}>{tenant.country || 'Global'}</p>
                          </div>
                        </div>
                      </TableCell>
                      <TableCell>
                        <code 
                          className="text-sm px-2 py-1 rounded"
                          style={{ backgroundColor: 'var(--sys-bg)', color: 'var(--sys-text-secondary)' }}
                        >
                          {tenant.code}
                        </code>
                      </TableCell>
                      <TableCell style={{ color: 'var(--sys-text-secondary)' }}>
                        {tenant.contactEmail || <span style={{ color: 'var(--sys-text-muted)' }}>-</span>}
                      </TableCell>
                      <TableCell>
                        <Badge 
                          className="border"
                          style={getPlanStyle(tenant.subscriptionPlan)}
                        >
                          {tenant.subscriptionPlan || 'standard'}
                        </Badge>
                      </TableCell>
                      <TableCell className="text-center">
                        <Badge 
                          className="border"
                          style={getStatusStyle(tenant.status)}
                        >
                          {tenant.status || 'active'}
                        </Badge>
                      </TableCell>
                      <TableCell style={{ color: 'var(--sys-text-muted)' }}>
                        {tenant.createdAt ? formatDate(tenant.createdAt) : '-'}
                      </TableCell>
                      <TableCell className="text-right">
                        <div className="flex items-center justify-end gap-1">
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => navigate(`/system/tenants/${tenant.id}`)}
                            title="View"
                            style={{ color: 'var(--sys-text-secondary)' }}
                          >
                            <Eye className="w-4 h-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => navigate(`/system/tenants/${tenant.id}/edit`)}
                            title="Edit"
                            style={{ color: 'var(--sys-text-secondary)' }}
                          >
                            <Edit className="w-4 h-4" />
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

