client/src/hooks/useSessionGuard.ts.content:
/**
 * useSessionGuard Hook - HARDENED Session Security
 * 
 * PHASE 3 HARDENED - Dec 2024
 * 
 * SECURITY GUARANTEES:
 * 1. Real-time scope mismatch detection
 * 2. Multi-tab session synchronization
 * 3. Role change detection during active session
 * 4. Automatic redirect on scope violation
 * 5. Session integrity validation
 * 
 * Usage:
 * Call this hook in any component that needs session security.
 * It will automatically handle scope changes and multi-tab scenarios.
 */

import { useEffect, useCallback, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { 
  getCurrentPanelFromPath, 
  isPanelAccessAllowed, 
  getScopeBasePath 
} from './useScopePath';

interface SessionGuardResult {
  isValid: boolean;
  isScopeMismatch: boolean;
  currentPanel: 'system' | 'admin' | 'app' | null;
  expectedPanel: 'system' | 'admin' | 'app';
  correctPath: string;
  forceRedirect: () => void;
}

const SCOPE_CHECK_INTERVAL = 5000;

export function useSessionGuard(): SessionGuardResult {
  const { user, isAuthenticated, validateSession, forceSessionRefresh } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();
  const [isValid, setIsValid] = useState(true);
  const [isScopeMismatch, setIsScopeMismatch] = useState(false);

  const userScope = user?.accessScope || 'branch';
  const currentPanel = getCurrentPanelFromPath(location.pathname);

  const expectedPanel = (() => {
    switch (userScope) {
      case 'system': return 'system' as const;
      case 'tenant': return 'admin' as const;
      default: return 'app' as const;
    }
  })();

  const correctPath = `${getScopeBasePath(userScope)}/dashboard`;

  const checkScopeMismatch = useCallback(() => {
    if (!user || !currentPanel) {
      setIsScopeMismatch(false);
      return false;
    }

    const hasAccess = isPanelAccessAllowed(user.accessScope, currentPanel);
    setIsScopeMismatch(!hasAccess);
    return !hasAccess;
  }, [user, currentPanel]);

  const forceRedirect = useCallback(() => {
    navigate(correctPath, { replace: true });
  }, [navigate, correctPath]);

  useEffect(() => {
    if (!isAuthenticated) {
      setIsValid(false);
      return;
    }

    const mismatch = checkScopeMismatch();
    if (mismatch) {
      setIsValid(false);
      const timer = setTimeout(() => {
        forceRedirect();
      }, 2000);
      return () => clearTimeout(timer);
    }

    setIsValid(true);
  }, [isAuthenticated, checkScopeMismatch, forceRedirect]);

  useEffect(() => {
    if (!isAuthenticated) return;

    const interval = setInterval(async () => {
      const sessionValid = await validateSession();
      if (!sessionValid) {
        navigate('/login', { replace: true });
      }
    }, SCOPE_CHECK_INTERVAL);

    return () => clearInterval(interval);
  }, [isAuthenticated, validateSession, navigate]);

  useEffect(() => {
    const handleVisibilityChange = async () => {
      if (document.visibilityState === 'visible' && isAuthenticated) {
        const sessionValid = await validateSession();
        if (!sessionValid) {
          navigate('/login', { replace: true });
          return;
        }

        checkScopeMismatch();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [isAuthenticated, validateSession, navigate, checkScopeMismatch]);

  useEffect(() => {
    const handleFocus = async () => {
      if (isAuthenticated) {
        const storedUser = localStorage.getItem('user');
        if (storedUser) {
          try {
            const parsedUser = JSON.parse(storedUser);
            if (user && parsedUser.accessScope !== user.accessScope) {
              forceSessionRefresh();
            }
          } catch {
          }
        }
      }
    };

    window.addEventListener('focus', handleFocus);
    return () => window.removeEventListener('focus', handleFocus);
  }, [isAuthenticated, user, forceSessionRefresh]);

  return {
    isValid,
    isScopeMismatch,
    currentPanel,
    expectedPanel,
    correctPath,
    forceRedirect,
  };
}

export function useScopeMismatchAlert(): {
  showAlert: boolean;
  message: string;
  onDismiss: () => void;
} {
  const { isScopeMismatch, expectedPanel, forceRedirect } = useSessionGuard();
  const [dismissed, setDismissed] = useState(false);

  const panelNames = {
    system: 'System Admin',
    admin: 'Tenant Admin',
    app: 'App',
  };

  return {
    showAlert: isScopeMismatch && !dismissed,
    message: `You don't have access to this area. Redirecting to ${panelNames[expectedPanel]} panel...`,
    onDismiss: () => {
      setDismissed(true);
      forceRedirect();
    },
  };
}

export default useSessionGuard;

server/src/middleware/routeMetadata.ts.content:
/**
 * Declarative Route Metadata System - Phase 5 Backend Hardening
 * 
 * REPLACES: Implicit panel detection via string matching in autoPanelGuard
 * 
 * PURPOSE:
 * ========
 * 1. Every route MUST explicitly declare its access requirements
 * 2. No route can exist without declaring panel/scope/auth requirements
 * 3. Eliminates fragile string pattern matching
 * 4. Enables compile-time verification of route protection
 * 5. Future-proof: new routes must declare metadata or fail fast
 * 
 * METADATA STRUCTURE:
 * ==================
 * {
 *   panel: 'system' | 'admin' | 'app',      // Which panel owns this route
 *   requireAuth: boolean,                    // Authentication required
 *   requiredScope?: AccessScope[],           // Allowed user scopes
 *   description?: string                     // Route purpose (for docs)
 * }
 * 
 * USAGE:
 * ======
 * router.get('/path', 
 *   routeMetadata({ panel: 'system', requireAuth: true, requiredScope: ['system'] }),
 *   authMiddleware,
 *   controller
 * );
 */

import { Request, Response, NextFunction } from 'express';
import { contextLogger } from '../core/context/contextLogger';

export type AccessScope = 'system' | 'tenant' | 'business_line' | 'branch' | 'mixed';
export type PanelType = 'system' | 'admin' | 'app' | 'public';

export interface RouteMetadata {
  panel: PanelType;
  requireAuth: boolean;
  requiredScope?: AccessScope[];
  description?: string;
}

// Registry to track all routes with metadata (for auditing)
const routeRegistry = new Map<string, RouteMetadata>();

/**
 * Gets panel access rules
 */
function isPanelAccessAllowed(userScope: AccessScope, panel: PanelType): boolean {
  switch (panel) {
    case 'system':
      return userScope === 'system';
    case 'admin':
      return userScope === 'system' || userScope === 'tenant';
    case 'app':
      return true; // All authenticated users can access app panel
    case 'public':
      return true; // Public routes (login, etc.)
    default:
      return false;
  }
}

/**
 * Logs access violations for audit trail
 */
function logAccessViolation(
  req: Request,
  reason: string,
  metadata: RouteMetadata,
  details: Record<string, unknown>
) {
  const logger = contextLogger.child({ module: 'routeMetadata' });
  logger.error('🚨 ROUTE ACCESS VIOLATION', {
    reason,
    path: req.path,
    method: req.method,
    requiredPanel: metadata.panel,
    requiredScope: metadata.requiredScope,
    userId: req.user?.userId,
    userScope: req.user?.accessScope,
    userTenantId: req.user?.tenantId,
    ip: req.ip,
    userAgent: req.get('user-agent'),
    ...details,
  });
}

/**
 * Declarative route metadata middleware
 * 
 * ENFORCES:
 * - Panel access control
 * - Scope validation
 * - Authentication requirements
 * 
 * MUST be the FIRST middleware on every route (before authMiddleware)
 * This attaches metadata to the request for downstream validation
 */
export function routeMetadata(metadata: RouteMetadata) {
  return (req: Request, res: Response, next: NextFunction) => {
    // Attach metadata to request for downstream middleware
    (req as any).routeMetadata = metadata;

    // Register route for auditing (only in development)
    if (process.env.NODE_ENV !== 'production') {
      const routeKey = `${req.method} ${req.route?.path || req.path}`;
      if (!routeRegistry.has(routeKey)) {
        routeRegistry.set(routeKey, metadata);
      }
    }

    next();
  };
}

/**
 * Route metadata enforcer middleware
 * 
 * CRITICAL ARCHITECTURAL PATTERN:
 * ===============================
 * This middleware MUST run AFTER authMiddleware to ensure:
 * 1. req.user is populated (if token is valid)
 * 2. Enforcement ALWAYS happens (even if auth fails)
 * 
 * KEY INSIGHT: This middleware runs REGARDLESS of auth outcome
 * - If requireAuth=true and no user → 401
 * - If requireAuth=false → allow through
 * - If user exists → validate scope/panel access
 * 
 * This ensures NO route can bypass authorization checks
 */
export function enforceRouteMetadata() {
  return (req: Request, res: Response, next: NextFunction) => {
    const metadata = (req as any).routeMetadata as RouteMetadata | undefined;
    const logger = contextLogger.child({ module: 'routeMetadata' });

    // If no metadata, route is misconfigured - FAIL FAST
    if (!metadata) {
      logger.error('🚨 CRITICAL: Route missing metadata declaration', {
        path: req.path,
        method: req.method,
      });
      return res.status(500).json({
        error: 'Internal server error: Route misconfiguration',
        code: 'ROUTE_METADATA_MISSING',
      });
    }

    // Check authentication requirement FIRST
    if (metadata.requireAuth && !req.user) {
      logger.warn('Unauthenticated access attempt to protected route', {
        path: req.path,
        method: req.method,
        panel: metadata.panel,
      });
      return res.status(401).json({
        error: 'Authentication required',
        code: 'AUTH_REQUIRED',
      });
    }

    // Public routes with no auth - allow immediately
    if (metadata.panel === 'public' && !metadata.requireAuth) {
      return next();
    }

    // If not authenticated and route doesn't require auth, allow
    if (!req.user && !metadata.requireAuth) {
      return next();
    }

    // From this point, user MUST be authenticated
    if (!req.user) {
      logger.error('LOGIC ERROR: User required but not authenticated', {
        path: req.path,
        metadata,
      });
      return res.status(401).json({
        error: 'Authentication required',
        code: 'AUTH_REQUIRED',
      });
    }

    const userScope = (req.user.accessScope || 'branch') as AccessScope;

    // Panel access validation
    if (!isPanelAccessAllowed(userScope, metadata.panel)) {
      logAccessViolation(req, 'Panel access denied', metadata, {
        userScope,
        requiredPanel: metadata.panel,
      });
      return res.status(403).json({
        error: `Access denied. You don't have permission to access ${metadata.panel} APIs.`,
        code: 'PANEL_ACCESS_DENIED',
      });
    }

    // Scope validation (if specified)
    if (metadata.requiredScope && metadata.requiredScope.length > 0) {
      if (!metadata.requiredScope.includes(userScope)) {
        logAccessViolation(req, 'Scope access denied', metadata, {
          userScope,
          requiredScope: metadata.requiredScope,
        });
        return res.status(403).json({
          error: 'Access denied. Insufficient permissions.',
          code: 'SCOPE_ACCESS_DENIED',
        });
      }
    }

    // All validations passed
    logger.debug('Route access granted', {
      path: req.path,
      method: req.method,
      panel: metadata.panel,
      userScope,
    });

    next();
  };
}

/**
 * Audit helper: Get all registered routes
 * Useful for verifying all routes have metadata
 */
export function getRouteRegistry(): Map<string, RouteMetadata> {
  return new Map(routeRegistry);
}

/**
 * Audit helper: Check for routes without metadata
 * Returns array of routes that may be unprotected
 */
export function auditRouteProtection(): string[] {
  const unprotectedRoutes: string[] = [];

  // In production, this would scan the Express router
  // For now, return empty array (registry tracks declared routes)

  return unprotectedRoutes;
}

// Export helper to create common metadata patterns
export const RoutePatterns = {
  systemOnly: (description?: string): RouteMetadata => ({
    panel: 'system',
    requireAuth: true,
    requiredScope: ['system'],
    description,
  }),

  adminPanel: (description?: string): RouteMetadata => ({
    panel: 'admin',
    requireAuth: true,
    requiredScope: ['system', 'tenant'],
    description,
  }),

  appPanel: (description?: string): RouteMetadata => ({
    panel: 'app',
    requireAuth: true,
    description,
  }),

  publicRoute: (description?: string): RouteMetadata => ({
    panel: 'public',
    requireAuth: false,
    description,
  }),
};

server/src/tests/security/routingIsolati.content:
/**
 * ROUTING ISOLATION SECURITY AUDIT - Comprehensive Test Suite
 * 
 * Tests absolute routing isolation across all three panels:
 * - System Panel (System Admins only)
 * - Tenant Admin Panel (Tenant Admins + System Admins)
 * - App Panel (All authenticated users)
 * 
 * Security Guarantees Tested:
 * 1. Panel-level access control
 * 2. Cross-tenant access prevention
 * 3. Token manipulation detection
 * 4. Authentication edge cases
 * 5. High-scale tenant isolation
 */

import { describe, test, expect, beforeAll, afterAll } from '@jest/globals';
import request from 'supertest';
import jwt from 'jsonwebtoken';

const API_BASE = process.env.API_URL || 'http://localhost:3000';
const SECRET = process.env.JWT_SECRET || 'your-secret-key';

interface TestUser {
  userId: string;
  accessScope: 'system' | 'tenant' | 'branch';
  tenantId: string | null;
  token: string;
}

describe('ROUTING ISOLATION AUDIT - Panel Access Control', () => {
  let systemAdmin: TestUser;
  let tenantAdmin: TestUser;
  let branchUser: TestUser;
  let differentTenantAdmin: TestUser;

  beforeAll(async () => {
    // Create test tokens for different user types
    systemAdmin = {
      userId: 'system-user-1',
      accessScope: 'system',
      tenantId: null,
      token: jwt.sign(
        {
          userId: 'system-user-1',
          accessScope: 'system',
          tenantId: null,
          role: 'system_admin',
        },
        SECRET,
        { expiresIn: '1h' }
      ),
    };

    tenantAdmin = {
      userId: 'tenant-admin-1',
      accessScope: 'tenant',
      tenantId: 'tenant-001',
      token: jwt.sign(
        {
          userId: 'tenant-admin-1',
          accessScope: 'tenant',
          tenantId: 'tenant-001',
          role: 'tenant_admin',
        },
        SECRET,
        { expiresIn: '1h' }
      ),
    };

    branchUser = {
      userId: 'branch-user-1',
      accessScope: 'branch',
      tenantId: 'tenant-001',
      token: jwt.sign(
        {
          userId: 'branch-user-1',
          accessScope: 'branch',
          tenantId: 'tenant-001',
          branchId: 'branch-001',
          role: 'user',
        },
        SECRET,
        { expiresIn: '1h' }
      ),
    };

    differentTenantAdmin = {
      userId: 'tenant-admin-2',
      accessScope: 'tenant',
      tenantId: 'tenant-002',
      token: jwt.sign(
        {
          userId: 'tenant-admin-2',
          accessScope: 'tenant',
          tenantId: 'tenant-002',
          role: 'tenant_admin',
        },
        SECRET,
        { expiresIn: '1h' }
      ),
    };
  });

  describe('1. System Panel API Access Control', () => {
    test('System admin CAN access /api/v1/tenants', async () => {
      const response = await request(API_BASE)
        .get('/api/v1/tenants')
        .set('Authorization', `Bearer ${systemAdmin.token}`);

      expect([200, 401]).toContain(response.status);
      if (response.status !== 401) {
        expect(response.status).toBe(200);
      }
    });

    test('Tenant admin CANNOT access /api/v1/tenants', async () => {
      const response = await request(API_BASE)
        .get('/api/v1/tenants')
        .set('Authorization', `Bearer ${tenantAdmin.token}`);

      expect(response.status).toBe(403);
      expect(response.body.code).toMatch(/PANEL_ACCESS_DENIED|AUTH_REQUIRED/);
    });

    test('Branch user CANNOT access /api/v1/tenants', async () => {
      const response = await request(API_BASE)
        .get('/api/v1/tenants')
        .set('Authorization', `Bearer ${branchUser.token}`);

      expect(response.status).toBe(403);
      expect(response.body.code).toMatch(/PANEL_ACCESS_DENIED|AUTH_REQUIRED/);
    });

    test('System admin CAN create tenants via /api/v1/hierarchy/tenants', async () => {
      const response = await request(API_BASE)
        .post('/api/v1/hierarchy/tenants')
        .set('Authorization', `Bearer ${systemAdmin.token}`)
        .send({
          name: 'Test Tenant',
          code: 'TEST-001',
        });

      expect([200, 201, 401, 403, 409]).toContain(response.status);
    });

    test('Tenant admin CANNOT create tenants', async () => {
      const response = await request(API_BASE)
        .post('/api/v1/hierarchy/tenants')
        .set('Authorization', `Bearer ${tenantAdmin.token}`)
        .send({
          name: 'Unauthorized Tenant',
          code: 'HACK-001',
        });

      expect(response.status).toBe(403);
    });
  });

  describe('2. Tenant Admin Panel API Access Control', () => {
    test('System admin CAN access tenant admin APIs', async () => {
      const response = await request(API_BASE)
        .get('/api/v1/business-lines')
        .set('Authorization', `Bearer ${systemAdmin.token}`);

      expect([200, 401]).toContain(response.status);
    });

    test('Tenant admin CAN access their own business lines', async () => {
      const response = await request(API_BASE)
        .get('/api/v1/business-lines')
        .set('Authorization', `Bearer ${tenantAdmin.token}`);

      expect([200, 401]).toContain(response.status);
    });

    test('Branch user CANNOT access admin panel APIs', async () => {
      const response = await request(API_BASE)
        .get('/api/v1/business-lines')
        .set('Authorization', `Bearer ${branchUser.token}`);

      expect(response.status).toBe(403);
      expect(response.body.code).toBe('PANEL_ACCESS_DENIED');
    });
  });

  describe('3. Cross-Tenant Access Prevention', () => {
    test('Tenant admin CANNOT access another tenant\'s data via URL manipulation', async () => {
      const response = await request(API_BASE)
        .get('/api/v1/business-lines?tenantId=tenant-002')
        .set('Authorization', `Bearer ${tenantAdmin.token}`);

      // Should either filter to their own tenant or deny access
      if (response.status === 200) {
        // If successful, verify data is filtered to correct tenant
        const data = response.body.data || response.body;
        if (Array.isArray(data)) {
          data.forEach((item: any) => {
            expect(item.tenantId).toBe(tenantAdmin.tenantId);
          });
        }
      } else {
        expect(response.status).toBe(403);
      }
    });

    test('Tenant admin CANNOT create resources in another tenant', async () => {
      const response = await request(API_BASE)
        .post('/api/v1/business-lines')
        .set('Authorization', `Bearer ${tenantAdmin.token}`)
        .send({
          name: 'Unauthorized Business Line',
          tenantId: 'tenant-002', // Different tenant!
        });

      expect(response.status).toBe(403);
    });
  });

  describe('4. Token Manipulation Detection', () => {
    test('Invalid token is rejected', async () => {
      const response = await request(API_BASE)
        .get('/api/v1/tenants')
        .set('Authorization', 'Bearer invalid-token');

      expect(response.status).toBe(401);
      expect(response.body.error).toMatch(/Invalid token|Authentication failed/);
    });

    test('Expired token is rejected', async () => {
      const expiredToken = jwt.sign(
        {
          userId: 'test-user',
          accessScope: 'system',
          tenantId: null,
        },
        SECRET,
        { expiresIn: '-1h' } // Already expired
      );

      const response = await request(API_BASE)
        .get('/api/v1/tenants')
        .set('Authorization', `Bearer ${expiredToken}`);

      expect(response.status).toBe(401);
      expect(response.body.error).toMatch(/Token expired|expired/i);
    });

    test('Missing token is rejected', async () => {
      const response = await request(API_BASE).get('/api/v1/tenants');

      expect(response.status).toBe(401);
      expect(response.body.error).toMatch(/No token provided|Authentication required/);
    });

    test('Token with manipulated scope is rejected by panel guard', async () => {
      // Attacker tries to elevate their scope
      const manipulatedToken = jwt.sign(
        {
          userId: branchUser.userId,
