server/src/core/safety/deduplicationMidd.content:
/**
 * Platform Core Layer - Request Deduplication Middleware
 * Phase 7: Concurrent Duplicate Request Prevention
 * 
 * Prevents duplicate concurrent requests with the same fingerprint
 * from being processed simultaneously. Unlike idempotency (which replays
 * cached responses), deduplication blocks concurrent duplicates and
 * makes them wait for the original request to complete.
 */

import { Request, Response, NextFunction } from 'express';
import { getRedisClient } from '../../services/redisClient';
import { contextLogger, RequestContext } from '../context';
import { createHash } from 'crypto';

const DEDUP_PREFIX = 'dedup:';
const DEFAULT_DEDUP_WINDOW = 5000;
const DEFAULT_WAIT_TIMEOUT = 10000;
const POLL_INTERVAL = 100;

interface DeduplicationOptions {
  windowMs?: number;
  waitTimeoutMs?: number;
  skipMethods?: string[];
  fingerprintGenerator?: (req: Request) => string;
}

interface DeduplicationRecord {
  fingerprint: string;
  status: 'processing' | 'completed';
  response?: unknown;
  statusCode?: number;
  startedAt: number;
  completedAt?: number;
}

export function createDeduplicationMiddleware(options: DeduplicationOptions = {}) {
  const {
    windowMs = DEFAULT_DEDUP_WINDOW,
    waitTimeoutMs = DEFAULT_WAIT_TIMEOUT,
    skipMethods = ['GET', 'HEAD', 'OPTIONS'],
    fingerprintGenerator = defaultFingerprintGenerator,
  } = options;

  return async (req: Request, res: Response, next: NextFunction) => {
    if (skipMethods.includes(req.method)) {
      return next();
    }

    const redis = getRedisClient();
    if (!redis) {
      return next();
    }

    const fingerprint = fingerprintGenerator(req);
    const dedupKey = `${DEDUP_PREFIX}${fingerprint}`;

    try {
      const existingRecord = await redis.get(dedupKey);

      if (existingRecord) {
        const record: DeduplicationRecord = JSON.parse(existingRecord);

        if (record.status === 'processing') {
          contextLogger.debug('Duplicate request detected, waiting for original', { fingerprint });

          const result = await waitForCompletion(redis, dedupKey, waitTimeoutMs);

          if (result) {
            contextLogger.debug('Returning deduplicated response', { fingerprint });
            res.setHeader('X-Deduplicated', 'true');
            return res.status(result.statusCode || 200).json(result.response);
          }

          contextLogger.warn('Wait timeout for duplicate request', { fingerprint });
        }

        if (record.status === 'completed' && record.response) {
          const age = Date.now() - (record.completedAt || record.startedAt);
          if (age < windowMs) {
            contextLogger.debug('Returning recently completed response', { fingerprint, age });
            res.setHeader('X-Deduplicated', 'true');
            return res.status(record.statusCode || 200).json(record.response);
          }
        }
      }

      const processingRecord: DeduplicationRecord = {
        fingerprint,
        status: 'processing',
        startedAt: Date.now(),
      };

      const setResult = await redis.set(
        dedupKey, 
        JSON.stringify(processingRecord), 
        'PX', 
        waitTimeoutMs + windowMs,
        'NX'
      );

      if (setResult !== 'OK') {
        return next();
      }

      const originalJson = res.json.bind(res);
      let responseHandled = false;

      res.json = function(body: any) {
        const statusCode = res.statusCode;
        responseHandled = true;

        setImmediate(async () => {
          try {
            const completedRecord: DeduplicationRecord = {
              fingerprint,
              status: 'completed',
              response: body,
              statusCode,
              startedAt: processingRecord.startedAt,
              completedAt: Date.now(),
            };
            await redis.set(dedupKey, JSON.stringify(completedRecord), 'PX', windowMs);
          } catch (error) {
            contextLogger.error('Failed to update deduplication record', { error, fingerprint });
          }
        });

        return originalJson(body);
      };

      res.on('close', async () => {
        if (!responseHandled) {
          try {
            await redis.del(dedupKey);
            contextLogger.debug('Cleared dedup record on early close', { fingerprint });
          } catch (error) {
            contextLogger.error('Failed to clear dedup record on close', { error, fingerprint });
          }
        }
      });

      next();
    } catch (error) {
      contextLogger.error('Deduplication middleware error', { error, fingerprint });
      next();
    }
  };
}

function defaultFingerprintGenerator(req: Request): string {
  const tenantId = RequestContext.getTenantId() || 'global';
  const userId = RequestContext.getUserId() || 'anonymous';

  const content = JSON.stringify({
    tenantId,
    userId,
    method: req.method,
    path: req.path,
    body: req.body,
  });

  return createHash('sha256').update(content).digest('hex').substring(0, 32);
}

async function waitForCompletion(
  redis: any,
  key: string,
  timeoutMs: number
): Promise<DeduplicationRecord | null> {
  const startTime = Date.now();

  while (Date.now() - startTime < timeoutMs) {
    const record = await redis.get(key);

    if (record) {
      const parsed: DeduplicationRecord = JSON.parse(record);
      if (parsed.status === 'completed') {
        return parsed;
      }
    } else {
      return null;
    }

    await new Promise(resolve => setTimeout(resolve, POLL_INTERVAL));
  }

  return null;
}

export function deduplicationMiddleware(options?: DeduplicationOptions) {
  return createDeduplicationMiddleware(options);
}

export default deduplicationMiddleware;

server/src/core/queue/queueService.ts.content:
/**
 * Platform Core Layer - BullMQ Queue Service
 * Phase 7: Enterprise Background Processing - AGI Task Engine
 * 
 * Features:
 * - 7 purpose-built queues for different workload types
 * - Exponential backoff retry policies
 * - Dead-letter queue for failed jobs
 * - Redis-based distributed processing
 * - Comprehensive metrics and event logging
 * - Multi-tenant job isolation
 */

import { Queue, Worker, Job, QueueEvents, FlowProducer } from 'bullmq';
import { getRedisClient } from '../../services/redisClient';
import { contextLogger } from '../context';
import {
  QueueName,
  QueueConfig,
  QUEUE_CONFIGS,
  DLQ_CONFIG,
  JobData,
  BaseJobData,
  QueueMetrics,
  WorkerHealth,
  ANIDecisionJobData,
  AGITaskJobData,
  PermissionRebuildJobData,
  AuditJobData,
  MailJobData,
  ReportingJobData,
  BulkOperationJobData,
} from './types';
import { ulid } from 'ulid';

class QueueService {
  private queues: Map<QueueName, Queue> = new Map();
  private workers: Map<QueueName, Worker> = new Map();
  private queueEvents: Map<QueueName, QueueEvents> = new Map();
  private deadLetterQueue: Queue | null = null;
  private flowProducer: FlowProducer | null = null;
  private isInitialized: boolean = false;
  private workerHealth: Map<QueueName, WorkerHealth> = new Map();
  private metricsBuffer: Map<QueueName, { processingTimes: number[]; errors: number; completed: number }> = new Map();

  async initialize(): Promise<void> {
    if (this.isInitialized) return;

    const redis = getRedisClient();
    if (!redis) {
      contextLogger.warn('Redis not available, queue service disabled');
      return;
    }

    const connection = {
      host: process.env.REDIS_HOST || 'localhost',
      port: parseInt(process.env.REDIS_PORT || '6379', 10),
      password: process.env.REDIS_PASSWORD,
    };

    try {
      for (const [name, config] of Object.entries(QUEUE_CONFIGS)) {
        const queue = new Queue(name, { connection, defaultJobOptions: config.defaultJobOptions });
        this.queues.set(name as QueueName, queue);

        const events = new QueueEvents(name, { connection });
        this.queueEvents.set(name as QueueName, events);
        this.setupQueueEventHandlers(name as QueueName, events);

        this.metricsBuffer.set(name as QueueName, { processingTimes: [], errors: 0, completed: 0 });

        contextLogger.info('Queue initialized', { queue: name });
      }

      this.deadLetterQueue = new Queue(DLQ_CONFIG.name, { connection });

      this.flowProducer = new FlowProducer({ connection });

      this.isInitialized = true;
      contextLogger.info('Queue service initialized', { queues: Object.keys(QUEUE_CONFIGS) });
    } catch (error) {
      contextLogger.error('Queue service initialization failed', { error });
      throw error;
    }
  }

  async addJob<T extends JobData>(
    queueName: QueueName,
    data: T,
    options?: { priority?: number; delay?: number; jobId?: string }
  ): Promise<{ enqueued: boolean; jobId?: string; reason?: string }> {
    if (!this.isInitialized) {
      contextLogger.warn('Queue service not initialized, job not added', { queue: queueName });
      return { enqueued: false, reason: 'queue_service_unavailable' };
    }

    const queue = this.queues.get(queueName);
    if (!queue) {
      contextLogger.warn('Queue not found, job not added', { queue: queueName });
      return { enqueued: false, reason: 'queue_not_found' };
    }

    const jobId = options?.jobId || `job_${ulid()}`;
    const jobData = {
      ...data,
      createdAt: data.createdAt || Date.now(),
    };

    try {
      const job = await queue.add(queueName, jobData, {
        jobId,
        priority: options?.priority,
        delay: options?.delay,
      });

      contextLogger.debug('Job added to queue', {
        queue: queueName,
        jobId: job.id,
        tenantId: data.tenantId,
      });

      return { enqueued: true, jobId: job.id! };
    } catch (error) {
      contextLogger.error('Failed to add job to queue', { queue: queueName, error });
      return { enqueued: false, reason: 'enqueue_failed' };
    }
  }

  async addANIDecision(data: Omit<ANIDecisionJobData, 'createdAt'>): Promise<{ enqueued: boolean; jobId?: string; reason?: string }> {
    return this.addJob('aniDecisionQueue', { ...data, createdAt: Date.now() });
  }

  async addAGITask(data: Omit<AGITaskJobData, 'createdAt'>): Promise<{ enqueued: boolean; jobId?: string; reason?: string }> {
    const priority = data.priority === 'critical' ? 1 : data.priority === 'high' ? 2 : data.priority === 'low' ? 4 : 3;
    return this.addJob('agiTaskQueue', { ...data, createdAt: Date.now() }, { priority });
  }

  async addPermissionRebuild(data: Omit<PermissionRebuildJobData, 'createdAt'>): Promise<{ enqueued: boolean; jobId?: string; reason?: string }> {
    return this.addJob('permissionRebuildQueue', { ...data, createdAt: Date.now() });
  }

  async addAuditLog(data: Omit<AuditJobData, 'createdAt'>): Promise<{ enqueued: boolean; jobId?: string; reason?: string }> {
    return this.addJob('auditQueue', { ...data, createdAt: Date.now() });
  }

  async addMail(data: Omit<MailJobData, 'createdAt'>): Promise<{ enqueued: boolean; jobId?: string; reason?: string }> {
    return this.addJob('mailQueue', { ...data, createdAt: Date.now() });
  }

  async addReport(data: Omit<ReportingJobData, 'createdAt'>): Promise<{ enqueued: boolean; jobId?: string; reason?: string }> {
    return this.addJob('reportingQueue', { ...data, createdAt: Date.now() });
  }

  async addBulkOperation(data: Omit<BulkOperationJobData, 'createdAt'>): Promise<{ enqueued: boolean; jobId?: string; reason?: string }> {
    return this.addJob('bulkOperationQueue', { ...data, createdAt: Date.now() });
  }

  isReady(): boolean {
    return this.isInitialized;
  }

  registerWorker<T extends JobData>(
    queueName: QueueName,
    processor: (job: Job<T>) => Promise<void>
  ): void {
    if (!this.isInitialized) {
      contextLogger.warn('Queue service not initialized, worker registration skipped', { queue: queueName });
      return;
    }

    const queue = this.queues.get(queueName);
    if (!queue) {
      contextLogger.warn('Queue not found, worker registration skipped', { queue: queueName });
      return;
    }

    const config = QUEUE_CONFIGS[queueName];
    if (!config) {
      throw new Error(`Unknown queue: ${queueName}`);
    }

    const connection = {
      host: process.env.REDIS_HOST || 'localhost',
      port: parseInt(process.env.REDIS_PORT || '6379', 10),
      password: process.env.REDIS_PASSWORD,
    };

    const worker = new Worker(
      queueName,
      async (job: Job<T>) => {
        const startTime = Date.now();
        const metrics = this.metricsBuffer.get(queueName);

        try {
          contextLogger.debug('Processing job', {
            queue: queueName,
            jobId: job.id,
            attempt: job.attemptsMade + 1,
          });

          await processor(job);

          const duration = Date.now() - startTime;
          if (metrics) {
            metrics.processingTimes.push(duration);
            metrics.completed++;
            if (metrics.processingTimes.length > 1000) {
              metrics.processingTimes.shift();
            }
          }

          this.updateWorkerHealth(queueName, 'running', job.id!);

          contextLogger.debug('Job completed', {
            queue: queueName,
            jobId: job.id,
            duration,
          });
        } catch (error) {
          if (metrics) {
            metrics.errors++;
          }

          contextLogger.error('Job processing failed', {
            queue: queueName,
            jobId: job.id,
            error,
            attempt: job.attemptsMade + 1,
          });

          throw error;
        }
      },
      { connection, concurrency: config.concurrency }
    );

    worker.on('failed', async (job, err) => {
      if (job) {
        const maxAttempts = job.opts.attempts || config.defaultJobOptions.attempts || 3;
        if (job.attemptsMade >= maxAttempts) {
          await this.moveToDeadLetter(queueName, job, err);
        }
      }
    });

    worker.on('error', (err) => {
      contextLogger.error('Worker error', { queue: queueName, error: err });
      this.updateWorkerHealth(queueName, 'error');
    });

    this.workers.set(queueName, worker);
    this.initializeWorkerHealth(queueName);

    contextLogger.info('Worker registered', { queue: queueName, concurrency: config.concurrency });
  }

  async getMetrics(queueName: QueueName): Promise<QueueMetrics> {
    const queue = this.queues.get(queueName);
    if (!queue || !this.isInitialized) {
      return {
        queueName,
        waiting: 0,
        active: 0,
        completed: 0,
        failed: 0,
        delayed: 0,
        processingTime: { avg: 0, p95: 0, p99: 0 },
        throughput: 0,
        errorRate: 0,
      };
    }

    const [waiting, active, completed, failed, delayed] = await Promise.all([
      queue.getWaitingCount(),
      queue.getActiveCount(),
      queue.getCompletedCount(),
      queue.getFailedCount(),
      queue.getDelayedCount(),
    ]);

    const buffer = this.metricsBuffer.get(queueName);
    const processingTimes = buffer?.processingTimes || [];
    const sortedTimes = [...processingTimes].sort((a, b) => a - b);

    return {
      queueName,
      waiting,
      active,
      completed,
      failed,
      delayed,
      processingTime: {
        avg: processingTimes.length > 0 ? processingTimes.reduce((a, b) => a + b, 0) / processingTimes.length : 0,
        p95: sortedTimes[Math.floor(sortedTimes.length * 0.95)] || 0,
        p99: sortedTimes[Math.floor(sortedTimes.length * 0.99)] || 0,
      },
      throughput: buffer?.completed || 0,
      errorRate: buffer ? (buffer.errors / (buffer.completed + buffer.errors) || 0) : 0,
    };
  }

  async getAllMetrics(): Promise<QueueMetrics[]> {
    const metrics: QueueMetrics[] = [];
    for (const queueName of this.queues.keys()) {
      metrics.push(await this.getMetrics(queueName));
    }
    return metrics;
  }

  getWorkerHealth(queueName: QueueName): WorkerHealth | undefined {
    return this.workerHealth.get(queueName);
  }

  getAllWorkerHealth(): WorkerHealth[] {
    return Array.from(this.workerHealth.values());
  }

  async pauseQueue(queueName: QueueName): Promise<void> {
    const queue = this.queues.get(queueName);
    if (queue) {
      await queue.pause();
      this.updateWorkerHealth(queueName, 'paused');
      contextLogger.info('Queue paused', { queue: queueName });
    }
  }

  async resumeQueue(queueName: QueueName): Promise<void> {
    const queue = this.queues.get(queueName);
    if (queue) {
      await queue.resume();
      this.updateWorkerHealth(queueName, 'running');
      contextLogger.info('Queue resumed', { queue: queueName });
    }
  }

  async retryFailedJobs(queueName: QueueName): Promise<number> {
    const queue = this.queues.get(queueName);
    if (!queue) return 0;

    const failed = await queue.getFailed();
    let retried = 0;

    for (const job of failed) {
      await job.retry();
      retried++;
    }

    contextLogger.info('Failed jobs retried', { queue: queueName, count: retried });
    return retried;
  }

  async shutdown(): Promise<void> {
    contextLogger.info('Shutting down queue service');

    for (const [name, worker] of this.workers) {
      await worker.close();
      contextLogger.debug('Worker closed', { queue: name });
    }

    for (const [name, events] of this.queueEvents) {
      await events.close();
    }

    for (const [name, queue] of this.queues) {
      await queue.close();
      contextLogger.debug('Queue closed', { queue: name });
    }

    if (this.deadLetterQueue) {
      await this.deadLetterQueue.close();
    }

    if (this.flowProducer) {
      await this.flowProducer.close();
    }

    this.isInitialized = false;
    contextLogger.info('Queue service shutdown complete');
  }

  private setupQueueEventHandlers(queueName: QueueName, events: QueueEvents): void {
    events.on('completed', ({ jobId }) => {
      contextLogger.debug('Job completed event', { queue: queueName, jobId });
    });

    events.on('failed', ({ jobId, failedReason }) => {
      contextLogger.warn('Job failed event', { queue: queueName, jobId, reason: failedReason });
    });

    events.on('stalled', ({ jobId }) => {
      contextLogger.warn('Job stalled', { queue: queueName, jobId });
    });

    events.on('progress', ({ jobId, data }) => {
      contextLogger.debug('Job progress', { queue: queueName, jobId, progress: data });
    });
  }

  private async moveToDeadLetter(queueName: QueueName, job: Job, error: Error): Promise<void> {
    if (!this.deadLetterQueue) {
      contextLogger.error('Dead letter queue not initialized, cannot move failed job', {
        queue: queueName,
        jobId: job.id,
      });
      return;
    }

    try {
      await this.deadLetterQueue.add('failed-job', {
        originalQueue: queueName,
        originalJobId: job.id,
        originalData: job.data,
        error: error.message,
        stack: error.stack,
        failedAt: Date.now(),
        attempts: job.attemptsMade,
        tenantId: (job.data as BaseJobData).tenantId,
        traceId: (job.data as BaseJobData).traceId,
      }, {
        removeOnComplete: { age: 86400 * 30 },
      });

      contextLogger.warn('Job moved to dead letter queue', {
        queue: queueName,
        jobId: job.id,
        error: error.message,
        attempts: job.attemptsMade,
      });
    } catch (dlqError) {
      contextLogger.error('Failed to move job to dead letter queue', {
        queue: queueName,
        jobId: job.id,
        error: dlqError,
      });
    }
  }

  private initializeWorkerHealth(queueName: QueueName): void {
    this.workerHealth.set(queueName, {
      queueName,
      workerId: `worker_${ulid()}`,
      status: 'running',
      jobsProcessed: 0,
      lastJobAt: null,
      uptime: Date.now(),
    });
  }

  private updateWorkerHealth(queueName: QueueName, status: WorkerHealth['status'], lastJobId?: string): void {
    const health = this.workerHealth.get(queueName);
    if (health) {
      health.status = status;
      if (lastJobId) {
        health.lastJobAt = Date.now();
        health.jobsProcessed++;
      }
    }
  }
}

export const queueService = new QueueService();
export default queueService;

server/src/core/safety/lockService.ts.content:
/**
 * Platform Core Layer - Distributed Lock Service
 * Phase 7: Redis-Based Distributed Locks for AGI Safety
 * 
 * Features:
 * - Redis SETNX-based distributed locks
 * - Automatic lock expiration
 * - Lock extension support
 * - Retry with exponential backoff
 * - Multi-tenant isolation
 * - AGI-safe concurrent operation protection
 */

import { getRedisClient } from '../../services/redisClient';
import { contextLogger } from '../context';
import { ulid } from 'ulid';
import {
  DistributedLock,
  LockOptions,
  LockResult,
  DEFAULT_LOCK_TTL,
  DEFAULT_LOCK_RETRY_COUNT,
  DEFAULT_LOCK_RETRY_DELAY,
} from './types';

class DistributedLockService {
  private readonly lockPrefix = 'dlock:';
  private readonly ownerId: string;
  private activeLocks: Map<string, DistributedLock> = new Map();

  constructor() {
    this.ownerId = `owner_${ulid()}`;
    this.startLockMonitor();
  }

  /**
   * Acquire a distributed lock
   */
  async acquire(key: string, options: LockOptions = {}): Promise<LockResult> {
    const {
      ttl = DEFAULT_LOCK_TTL,
      retryCount = DEFAULT_LOCK_RETRY_COUNT,
      retryDelay = DEFAULT_LOCK_RETRY_DELAY,
    } = options;

    const redis = getRedisClient();
    if (!redis) {
      contextLogger.warn('Redis not available, lock not acquired', { key });
      return { acquired: false };
    }

    const lockKey = `${this.lockPrefix}${key}`;
    const lockValue = JSON.stringify({
      owner: this.ownerId,
      acquiredAt: Date.now(),
      expiresAt: Date.now() + ttl,
    });

    for (let attempt = 0; attempt <= retryCount; attempt++) {
      try {
        const result = await redis.set(lockKey, lockValue, 'PX', ttl, 'NX');

        if (result === 'OK') {
          const lock: DistributedLock = {
            key,
            owner: this.ownerId,
            acquiredAt: Date.now(),
            expiresAt: Date.now() + ttl,
            renewCount: 0,
          };

          this.activeLocks.set(key, lock);

          contextLogger.debug('Lock acquired', { key, owner: this.ownerId, ttl });

          return { acquired: true, lock };
        }

        const existingLock = await redis.get(lockKey);
        if (existingLock) {
          try {
            const parsed = JSON.parse(existingLock);
            if (attempt === retryCount) {
              return { acquired: false, existingOwner: parsed.owner };
            }
          } catch {
            // Lock value corrupted, continue retry
          }
        }

        if (attempt < retryCount) {
          const delay = retryDelay * Math.pow(2, attempt);
          await this.sleep(delay);
        }
      } catch (error) {
        contextLogger.error('Lock acquisition error', { key, error, attempt });

        if (attempt === retryCount) {
          return { acquired: false };
        }
      }
    }

    return { acquired: false };
  }

  /**
   * Release a distributed lock
   */
  async release(key: string): Promise<boolean> {
    const redis = getRedisClient();
    if (!redis) {
      this.activeLocks.delete(key);
      return true;
    }

    const lockKey = `${this.lockPrefix}${key}`;

    try {
      const existingLock = await redis.get(lockKey);
      if (!existingLock) {
        this.activeLocks.delete(key);
        return true;
      }

      const parsed = JSON.parse(existingLock);
      if (parsed.owner !== this.ownerId) {
        contextLogger.warn('Cannot release lock owned by another process', {
          key,
          owner: this.ownerId,
          lockOwner: parsed.owner,
        });
        return false;
      }

      await redis.del(lockKey);
      this.activeLocks.delete(key);

      contextLogger.debug('Lock released', { key, owner: this.ownerId });
      return true;
    } catch (error) {
      contextLogger.error('Lock release error', { key, error });
      return false;
    }
  }

  /**
   * Extend lock TTL
   */
  async extend(key: string, additionalTtl?: number): Promise<boolean> {
    const redis = getRedisClient();
    if (!redis) return false;

    const lock = this.activeLocks.get(key);
    if (!lock) {
      contextLogger.warn('Cannot extend non-existent lock', { key });
      return false;
    }

    const lockKey = `${this.lockPrefix}${key}`;
    const ttl = additionalTtl || DEFAULT_LOCK_TTL;

    try {
      const existingLock = await redis.get(lockKey);
      if (!existingLock) {
        this.activeLocks.delete(key);
        return false;
      }

      const parsed = JSON.parse(existingLock);
      if (parsed.owner !== this.ownerId) {
        return false;
      }

      const newExpiry = Date.now() + ttl;
      const newValue = JSON.stringify({
        ...parsed,
        expiresAt: newExpiry,
      });

      await redis.set(lockKey, newValue, 'PX', ttl);

      lock.expiresAt = newExpiry;
      lock.renewCount++;

      contextLogger.debug('Lock extended', { key, newExpiry, renewCount: lock.renewCount });
      return true;
    } catch (error) {
      contextLogger.error('Lock extension error', { key, error });
      return false;
    }
  }

  /**
   * Check if lock is held by current owner
   */
  async isHeld(key: string): Promise<boolean> {
    const redis = getRedisClient();
    if (!redis) return this.activeLocks.has(key);

    const lockKey = `${this.lockPrefix}${key}`;

    try {
      const existingLock = await redis.get(lockKey);
      if (!existingLock) return false;

      const parsed = JSON.parse(existingLock);
      return parsed.owner === this.ownerId;
    } catch (error) {
      return false;
    }
  }

  /**
   * Execute function with lock
   */
  async withLock<T>(
    key: string,
    fn: () => Promise<T>,
    options: LockOptions = {}
  ): Promise<{ success: boolean; result?: T; error?: Error }> {
    const lockResult = await this.acquire(key, options);

    if (!lockResult.acquired) {
      return {
        success: false,
        error: new Error(`Failed to acquire lock: ${key}`),
      };
    }

    try {
      const result = await fn();
      return { success: true, result };
    } catch (error) {
      return { success: false, error: error as Error };
    } finally {
      await this.release(key);
    }
  }

  /**
   * Get current owner ID
   */
  getOwnerId(): string {
    return this.ownerId;
  }

  /**
   * Get all active locks for this instance
   */
  getActiveLocks(): DistributedLock[] {
    return Array.from(this.activeLocks.values());
  }

  /**
   * Release all locks held by this instance
   */
  async releaseAll(): Promise<void> {
    const keys = Array.from(this.activeLocks.keys());

    for (const key of keys) {
      await this.release(key);
    }

    contextLogger.info('All locks released', { count: keys.length });
  }

  private startLockMonitor(): void {
    setInterval(() => {
      const now = Date.now();

      for (const [key, lock] of this.activeLocks.entries()) {
        if (now > lock.expiresAt) {
          this.activeLocks.delete(key);
          contextLogger.debug('Expired lock removed from tracking', { key });
        }
      }
    }, 10 * 1000);
  }

  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

export const lockService = new DistributedLockService();
export default lockService;

