/**
 * Virtualized List Component
 * Phase 7: Frontend High-Throughput Optimization
 * 
 * Implements react-window for efficient rendering of large lists.
 * Supports variable item sizes, infinite scrolling, and custom renderers.
 */

import React, { memo, useCallback, useRef, useEffect, useState } from 'react';
import { FixedSizeList, VariableSizeList, ListChildComponentProps } from 'react-window';

export interface VirtualizedListItem {
  id: string;
  [key: string]: unknown;
}

export interface VirtualizedListProps<T extends VirtualizedListItem> {
  items: T[];
  height: number;
  itemHeight: number | ((index: number) => number);
  renderItem: (item: T, index: number, style: React.CSSProperties) => React.ReactNode;
  onLoadMore?: () => void;
  loadMoreThreshold?: number;
  isLoading?: boolean;
  emptyMessage?: string;
  className?: string;
  overscanCount?: number;
}

interface RowProps<T extends VirtualizedListItem> {
  data: {
    items: T[];
    renderItem: (item: T, index: number, style: React.CSSProperties) => React.ReactNode;
  };
  index: number;
  style: React.CSSProperties;
}

const MemoizedRow = memo(function Row<T extends VirtualizedListItem>({
  data,
  index,
  style,
}: RowProps<T>) {
  const { items, renderItem } = data;
  const item = items[index];

  if (!item) {
    return (
      <div style={style} className="flex items-center justify-center">
        <div className="w-6 h-6 border-2 border-[var(--sys-primary)] border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return <>{renderItem(item, index, style)}</>;
}) as <T extends VirtualizedListItem>(props: RowProps<T>) => JSX.Element;

export function VirtualizedList<T extends VirtualizedListItem>({
  items,
  height,
  itemHeight,
  renderItem,
  onLoadMore,
  loadMoreThreshold = 10,
  isLoading = false,
  emptyMessage = 'No items to display',
  className = '',
  overscanCount = 5,
}: VirtualizedListProps<T>) {
  const listRef = useRef<FixedSizeList | VariableSizeList>(null);
  const [containerWidth, setContainerWidth] = useState(0);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const updateWidth = () => {
      if (containerRef.current) {
        setContainerWidth(containerRef.current.offsetWidth);
      }
    };

    updateWidth();
    window.addEventListener('resize', updateWidth);
    return () => window.removeEventListener('resize', updateWidth);
  }, []);

  const handleItemsRendered = useCallback(
    ({ visibleStopIndex }: { visibleStopIndex: number }) => {
      if (
        onLoadMore &&
        !isLoading &&
        items.length > 0 &&
        visibleStopIndex >= items.length - loadMoreThreshold
      ) {
        onLoadMore();
      }
    },
    [onLoadMore, isLoading, items.length, loadMoreThreshold]
  );

  const itemData = { items, renderItem };

  if (items.length === 0 && !isLoading) {
    return (
      <div
        ref={containerRef}
        className={`flex items-center justify-center h-[${height}px] ${className}`}
        style={{ height }}
      >
        <p className="text-[var(--sys-text-secondary)]">{emptyMessage}</p>
      </div>
    );
  }

  const isVariableSize = typeof itemHeight === 'function';

  return (
    <div ref={containerRef} className={className}>
      {isVariableSize ? (
        <VariableSizeList
          ref={listRef as React.RefObject<VariableSizeList>}
          height={height}
          width={containerWidth || '100%'}
          itemCount={items.length}
          itemSize={itemHeight as (index: number) => number}
          itemData={itemData}
          onItemsRendered={handleItemsRendered}
          overscanCount={overscanCount}
        >
          {MemoizedRow as React.ComponentType<ListChildComponentProps>}
        </VariableSizeList>
      ) : (
        <FixedSizeList
          ref={listRef as React.RefObject<FixedSizeList>}
          height={height}
          width={containerWidth || '100%'}
          itemCount={items.length}
          itemSize={itemHeight as number}
          itemData={itemData}
          onItemsRendered={handleItemsRendered}
          overscanCount={overscanCount}
        >
          {MemoizedRow as React.ComponentType<ListChildComponentProps>}
        </FixedSizeList>
      )}
      {isLoading && (
        <div className="flex items-center justify-center py-4">
          <div className="w-6 h-6 border-2 border-[var(--sys-primary)] border-t-transparent rounded-full animate-spin" />
        </div>
      )}
    </div>
  );
}

export default VirtualizedList;

server/src/core/safety/idempotencyMiddle.content:
/**
 * Platform Core Layer - Idempotency Middleware
 * Phase 7: Request Deduplication & Distributed Transaction Safety
 * 
 * Features:
 * - Idempotency key support via X-Idempotency-Key header
 * - Automatic request fingerprinting
 * - Response caching for duplicate requests
 * - Multi-tenant isolation
 * - AGI-safe concurrent write protection
 */

import { Request, Response, NextFunction } from 'express';
import { getRedisClient } from '../../services/redisClient';
import { contextLogger, RequestContext } from '../context';
import { createHash } from 'crypto';
import {
  IdempotencyRecord,
  IdempotencyOptions,
  DEFAULT_IDEMPOTENCY_TTL,
} from './types';

const IDEMPOTENCY_PREFIX = 'idempotency:';

export function createIdempotencyMiddleware(options: IdempotencyOptions = {}) {
  const {
    ttl = DEFAULT_IDEMPOTENCY_TTL,
    skipMethods = ['GET', 'HEAD', 'OPTIONS'],
    keyGenerator = defaultKeyGenerator,
    responseSerializer = defaultResponseSerializer,
  } = options;

  return async (req: Request, res: Response, next: NextFunction) => {
    if (skipMethods.includes(req.method)) {
      return next();
    }

    const idempotencyKey = req.headers['x-idempotency-key'] as string;
    if (!idempotencyKey) {
      return next();
    }

    const redis = getRedisClient();
    if (!redis) {
      return next();
    }

    const tenantId = RequestContext.getTenantId();
    const userId = RequestContext.getUserId();
    const fullKey = `${IDEMPOTENCY_PREFIX}${tenantId || 'global'}:${idempotencyKey}`;
    const requestHash = generateRequestHash(req);

    try {
      const existingRecord = await redis.get(fullKey);

      if (existingRecord) {
        const record: IdempotencyRecord = JSON.parse(existingRecord);

        if (record.requestHash && record.requestHash !== requestHash) {
          contextLogger.warn('Idempotency key reused with different request', {
            key: idempotencyKey,
            tenantId,
          });
          return res.status(422).json({
            error: 'Idempotency key reused with different request parameters',
            code: 'IDEMPOTENCY_KEY_CONFLICT',
          });
        }

        if (record.status === 'pending') {
          contextLogger.debug('Request in progress, returning 409', { key: idempotencyKey });
          return res.status(409).json({
            error: 'Request with this idempotency key is still being processed',
            code: 'IDEMPOTENCY_REQUEST_IN_PROGRESS',
          });
        }

        if (record.status === 'completed' && record.response) {
          contextLogger.debug('Returning cached idempotent response', { key: idempotencyKey });
          res.setHeader('X-Idempotency-Replayed', 'true');
          const statusCode = record.statusCode || 200;
          return res.status(statusCode).json(record.response);
        }

        if (record.status === 'failed') {
          contextLogger.debug('Previous request failed, allowing retry', { key: idempotencyKey });
        }
      }

      const pendingRecord: IdempotencyRecord = {
        key: idempotencyKey,
        status: 'pending',
        createdAt: Date.now(),
        tenantId: tenantId || undefined,
        userId: userId || undefined,
        requestHash,
      };

      await redis.set(fullKey, JSON.stringify(pendingRecord), 'PX', ttl);

      const originalJson = res.json.bind(res);
      res.json = function(body: any) {
        const statusCode = res.statusCode;

        setImmediate(async () => {
          try {
            if (statusCode >= 200 && statusCode < 300) {
              const completedRecord: IdempotencyRecord = {
                ...pendingRecord,
                status: 'completed',
                response: responseSerializer(body),
                statusCode,
                completedAt: Date.now(),
              };
              await redis.set(fullKey, JSON.stringify(completedRecord), 'PX', ttl);

              contextLogger.debug('Idempotent response cached', { 
                key: idempotencyKey, 
                statusCode,
              });
            } else {
              const failedRecord: IdempotencyRecord = {
                ...pendingRecord,
                status: 'failed',
                error: body?.error || 'Request failed',
                completedAt: Date.now(),
              };
              await redis.set(fullKey, JSON.stringify(failedRecord), 'PX', Math.min(ttl, 60 * 1000));
            }
          } catch (error) {
            contextLogger.error('Failed to update idempotency record', { error, key: idempotencyKey });
          }
        });

        return originalJson(body);
      };

      next();
    } catch (error) {
      contextLogger.error('Idempotency middleware error', { error, key: idempotencyKey });
      next();
    }
  };
}

function defaultKeyGenerator(req: Request): string {
  const tenantId = RequestContext.getTenantId();
  const userId = RequestContext.getUserId();
  return `${tenantId}:${userId}:${req.method}:${req.path}`;
}

function defaultResponseSerializer(result: any): unknown {
  if (result === undefined || result === null) {
    return null;
  }

  try {
    return JSON.parse(JSON.stringify(result));
  } catch {
    return { serialized: false };
  }
}

function generateRequestHash(req: Request): string {
  const content = JSON.stringify({
    method: req.method,
    path: req.path,
    body: req.body,
    query: req.query,
  });

  return createHash('sha256').update(content).digest('hex').substring(0, 32);
}

export function idempotencyMiddleware(options?: IdempotencyOptions) {
  return createIdempotencyMiddleware(options);
}

export default idempotencyMiddleware;

server/src/core/metrics/queryLogger.ts.content:
/**
 * Platform Core Layer - Query Logger & Instrumentation
 * Phase 7: Slow Query Detection
 * 
 * Wraps database queries with timing instrumentation
 * and automatic slow query detection.
 */

import { metricsCollector } from './metricsCollector';
import { contextLogger, RequestContext } from '../context';
import { SLOW_QUERY_THRESHOLD_MS } from './types';

export interface QueryContext {
  tenantId?: string;
  userId?: string;
  traceId?: string;
}

export async function instrumentQuery<T>(
  queryName: string,
  queryFn: () => Promise<T>,
  context?: QueryContext
): Promise<T> {
  const startTime = performance.now();
  const traceId = context?.traceId || RequestContext.getTraceId();
  const tenantId = context?.tenantId || RequestContext.getTenantId();
  const userId = context?.userId || RequestContext.getUserId();

  try {
    const result = await queryFn();
    const duration = performance.now() - startTime;

    metricsCollector.recordQuery(queryName, duration, {
      tenantId: tenantId || undefined,
      userId: userId || undefined,
      traceId: traceId || undefined,
    });

    return result;
  } catch (error) {
    const duration = performance.now() - startTime;

    metricsCollector.recordQuery(`${queryName}:error`, duration, {
      tenantId: tenantId || undefined,
      userId: userId || undefined,
      traceId: traceId || undefined,
    });

    contextLogger.error('Query failed', {
      query: queryName,
      duration,
      error,
      tenantId,
      userId,
      traceId,
    });

    throw error;
  }
}

export function createQueryWrapper<TArgs extends any[], TResult>(
  queryName: string,
  queryFn: (...args: TArgs) => Promise<TResult>
): (...args: TArgs) => Promise<TResult> {
  return async (...args: TArgs): Promise<TResult> => {
    return instrumentQuery(queryName, () => queryFn(...args));
  };
}

export class QueryTimer {
  private startTime: number;
  private queryName: string;
  private context?: QueryContext;

  constructor(queryName: string, context?: QueryContext) {
    this.queryName = queryName;
    this.context = context;
    this.startTime = performance.now();
  }

  end(success: boolean = true): number {
    const duration = performance.now() - this.startTime;
    const name = success ? this.queryName : `${this.queryName}:error`;

    metricsCollector.recordQuery(name, duration, {
      tenantId: this.context?.tenantId || RequestContext.getTenantId() || undefined,
      userId: this.context?.userId || RequestContext.getUserId() || undefined,
      traceId: this.context?.traceId || RequestContext.getTraceId() || undefined,
    });

    return duration;
  }
}

export default instrumentQuery;

